// MedMasters: Gynae & Obs Paper 2: Biochemistry in Obs & Gynae
// 120 MCQs | Carbohydrate Metabolism, Lipid Metabolism, Steroidogenesis
(function(){
  if(!window.MM) window.MM={};
  window.MM['gynae_p2_biochem'] = [
    // Q1 , A=Increased glucose uptake by tissues (keep, rotate next if needed)
  {q:'Which metabolic effect of insulin is most important for maintaining maternal glucose homeostasis?',
  o:['Increased ketone body formation','Increased glycogen breakdown','Increased glucose uptake by tissues','Increased gluconeogenesis'],a:2,
  e:`Insulin promotes glucose uptake by peripheral tissues , especially skeletal muscle and adipose tissue , as its primary glucose-lowering action, maintaining maternal normoglycaemia in the fed state.<br><br>This is mediated by GLUT-4 translocation to the plasma membrane via the PI3K-Akt signalling pathway, allowing facilitated diffusion of glucose into insulin-sensitive cells.<br><br>Ketone body formation (A) and gluconeogenesis (D) are increased when insulin is absent; glycogen breakdown (B) is actively suppressed by insulin.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q2 , B=Glycogen
  {q:'Insulin promotes storage of glucose in the liver mainly in the form of:',
  o:['Fatty acids','Glycogen','Amino acids','Ketone bodies'],a:1,
  e:`Glycogen is the primary storage form of glucose in the liver, synthesised from glucose-6-phosphate via the action of glycogen synthase, which is activated by insulin through dephosphorylation.<br><br>Hepatic glycogen serves as the main short-term glucose reservoir, rapidly mobilised during fasting through glycogenolysis to maintain blood glucose between meals.<br><br>Fatty acids (A) are a secondary storage product requiring excess glucose; amino acids (C) are not a storage form of glucose; ketone bodies (D) are produced when insulin levels are low and fatty acid oxidation dominates.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q3 , C=GLUT-4 (rotate to A for distribution balance)
  {q:'Insulin promotes glucose uptake in skeletal muscle mainly by stimulating:',
  o:['GLUT-4 transporters','Sodium-glucose cotransporters','GLUT-2 transporters','GLUT-1 transporters'],a:0,
  e:`GLUT-4 is the insulin-sensitive glucose transporter that translocates from intracellular vesicles to the plasma membrane of skeletal muscle and adipose tissue in response to insulin signalling via the PI3K-Akt pathway.<br><br>Skeletal muscle accounts for approximately 75% of insulin-stimulated glucose disposal in the post-prandial state, making GLUT-4 translocation the dominant mechanism for peripheral glucose clearance.<br><br>Sodium-glucose cotransporters (B) mediate renal glucose reabsorption; GLUT-2 (C) facilitates glucose sensing in hepatocytes and pancreatic beta cells; GLUT-1 (D) mediates basal glucose uptake in the brain and red blood cells independently of insulin.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q4 , D=Gluconeogenesis (keep)
  {q:'Which metabolic pathway is inhibited by insulin in the liver?',
  o:['Glycogenesis','Glycolysis','Lipogenesis','Gluconeogenesis'],a:3,
  e:`Insulin suppresses hepatic gluconeogenesis by inhibiting the transcription of key gluconeogenic enzymes including phosphoenolpyruvate carboxykinase (PEPCK) and glucose-6-phosphatase, via the PI3K-Akt-FoxO1 signalling cascade.<br><br>This action prevents inappropriate hepatic glucose output in the fed state, complementing peripheral glucose uptake to maintain normoglycaemia after meals.<br><br>Glycogenesis (A), glycolysis (B) and lipogenesis (C) are all stimulated , not inhibited , by insulin, as part of its coordinated anabolic response to nutrient surplus.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q5 , B=Liver and adipose tissue (rotate to C for distribution)
  {q:'Insulin stimulates fatty acid synthesis primarily in:',
  o:['Brain','Skeletal muscle','Liver and adipose tissue','Kidney'],a:2,
  e:`De novo lipogenesis occurs primarily in the liver and adipose tissue, where insulin activates acetyl-CoA carboxylase , the rate-limiting enzyme , and fatty acid synthase via the PI3K-Akt signalling pathway and SREBP-1c transcription factor induction.<br><br>In the liver, citrate exported from the mitochondrial TCA cycle provides the cytoplasmic acetyl-CoA substrate for fatty acid synthesis, linking glucose oxidation directly to fat storage in the post-prandial state.<br><br>The brain (A) relies on glucose and ketone bodies, not lipogenesis; skeletal muscle (B) has minimal lipogenic capacity; the kidney (D) is not a primary site of insulin-stimulated fatty acid synthesis.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q6 , A=Increased maternal lipolysis and gluconeogenesis (keep)
  {q:'A pregnant woman in the third trimester develops physiological insulin resistance. Which metabolic adaptation ensures adequate fetal glucose supply?',
  o:['Increased maternal lipolysis and gluconeogenesis','Increased maternal glucose uptake','Reduced hepatic glucose output','Increased maternal glycogen storage'],a:0,
  e:`Physiological insulin resistance in late pregnancy , driven by placental hormones including human placental lactogen, progesterone and cortisol , shifts maternal metabolism toward lipolysis and gluconeogenesis, increasing circulating free fatty acids and glucose available for the feto-placental unit.<br><br>This "accelerated starvation" pattern ensures the fetus receives a continuous glucose supply even during maternal fasting, at the cost of increased maternal ketone body production.<br><br>Increased glucose uptake (B) and glycogen storage (D) are insulin-stimulated actions that would reduce, not preserve, circulating glucose for the fetus; reduced hepatic glucose output (C) would similarly impair fetal glucose supply.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q7 , C=Increased glycogen synthesis and fat deposition (keep)
  {q:'A fetus of a diabetic mother develops macrosomia due to excessive fetal insulin action. Which metabolic processes are primarily responsible?',
  o:['Increased ketone body production','Increased gluconeogenesis','Increased glycogen synthesis and fat deposition','Increased lipolysis'],a:2,
  e:`Fetal hyperinsulinaemia , triggered by chronic maternal hyperglycaemia crossing the placenta , drives anabolic metabolism in fetal tissues.<br><br>Glycogen synthase is activated, promoting glycogen storage in liver and myocardium, while lipogenesis is enhanced, depositing fat particularly in the abdomen and subcutaneous tissues.<br><br>Ketone body production (A), gluconeogenesis (B) and lipolysis (D) are all counter-insulin catabolic pathways suppressed by the excess fetal insulin.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q8 , B=Ketogenesis (rotate to D for balance)
  {q:'A pregnant woman with uncontrolled diabetes develops ketoacidosis. Which metabolic pathway is primarily overactive?',
  o:['Glycolysis','Lipogenesis','Glycogenesis','Ketogenesis'],a:3,
  e:`Severe insulin deficiency redirects acetyl-CoA , produced from excessive hepatic beta-oxidation of free fatty acids released by unrestrained lipolysis , away from the TCA cycle and into HMG-CoA synthesis via HMG-CoA synthase, generating ketone bodies (acetoacetate and beta-hydroxybutyrate) in excess of peripheral utilisation.<br><br>In diabetic ketoacidosis, this produces a high-anion-gap metabolic acidosis; in pregnancy, DKA can develop at lower blood glucose levels and progress more rapidly due to the physiological alterations in buffering capacity.<br><br>Glycolysis (A) is impaired by insulin deficiency; lipogenesis (B) and glycogenesis (C) require insulin and are therefore suppressed in this state.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q9 , D=Increased triglyceride synthesis (keep)
  {q:'Which metabolic effect of insulin in adipose tissue contributes to energy storage between meals?',
  o:['Increased fatty acid oxidation','Increased triglyceride synthesis','Increased ketogenesis','Increased lipolysis'],a:1,
  e:`In adipose tissue, insulin promotes triglyceride synthesis by stimulating glucose uptake via GLUT-4, activating lipoprotein lipase to hydrolyse circulating VLDL-triglycerides for fatty acid uptake, and inhibiting hormone-sensitive lipase to prevent intracellular triglyceride breakdown.<br><br>Together these actions trap fatty acids within adipocytes as stored triglycerides, constituting the primary long-term energy reservoir replenished after each meal.<br><br>Fatty acid oxidation (A), lipolysis (D) and ketogenesis (C) are all catabolic processes driven by insulin deficiency or glucagon excess , all are actively suppressed by insulin in adipose tissue.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q10 , C=Increased fetal insulin secretion (keep)
  {q:'A pregnant patient with gestational diabetes has high maternal glucose levels. What is the primary mechanism causing increased fetal growth?',
  o:['Reduced fetal insulin production','Increased fetal cortisol secretion','Increased fetal insulin secretion','Increased fetal glucagon secretion'],a:2,
  e:`Maternal glucose crosses the placenta freely by facilitated diffusion via GLUT-1 transporters; fetal glucose levels therefore mirror maternal levels. Chronic fetal hyperglycaemia stimulates hypertrophy of fetal pancreatic beta cells, resulting in increased fetal insulin secretion.<br><br>This fetal hyperinsulinaemia then acts as the primary anabolic driver of macrosomia, promoting glycogen storage, lipogenesis and organ hypertrophy throughout the second and third trimesters.<br><br>Fetal insulin production is increased, not reduced (A); cortisol (B) is catabolic and would not drive growth; glucagon (D) opposes insulin action and promotes glycogenolysis and gluconeogenesis.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q11 , C=Glycogenesis , rotate to A to break Q10=C,Q11=C
  {q:'A pregnant woman with gestational diabetes delivers a macrosomic infant. Which fetal metabolic pathway is primarily responsible for the excessive fat and glycogen accumulation?',
  o:['Glycogenesis','Glycogenolysis','Ketogenesis','Gluconeogenesis'],a:0,
  e:`Glycogenesis , the synthesis of glycogen from glucose-6-phosphate via glycogen synthase , is the primary pathway responsible for the excessive glycogen accumulation in the liver, myocardium and skeletal muscle of infants of diabetic mothers.<br><br>Fetal hyperinsulinaemia activates glycogen synthase by dephosphorylation while simultaneously inhibiting glycogen phosphorylase, creating a net shift toward glycogen storage that is pathologically amplified in the setting of chronic glucose oversupply.<br><br>Glycogenolysis (B) is the reverse process, inhibited by insulin; ketogenesis (C) requires insulin deficiency; gluconeogenesis (D) is suppressed by the excess fetal insulin.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q12 , D=Insulin , keep
  {q:'A fetus exposed to chronic maternal hyperglycemia stores large amounts of glycogen in the liver and myocardium. Which fetal hormone is primarily responsible?',
  o:['Cortisol','Thyroxine','Glucagon','Insulin'],a:3,
  e:`Fetal insulin is the primary anabolic hormone driving glycogen storage in infants of diabetic mothers: glucose crossing the placenta stimulates fetal beta cells to secrete excess insulin, which activates glycogen synthase and suppresses glycogen phosphorylase in fetal liver, myocardium and skeletal muscle.<br><br>Myocardial glycogen accumulation is a recognised feature of infants of diabetic mothers and can contribute to hypertrophic cardiomyopathy detected on fetal echocardiography.<br><br>Cortisol (A) promotes gluconeogenesis and glycogenolysis; thyroxine (B) regulates metabolic rate but does not drive glycogen synthesis; glucagon (C) is the principal glycogenolytic hormone and opposes glycogen storage.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q13 , D=Gluconeogenesis , rotate to B to break Q12=D,Q13=D
  {q:'In maternal metabolism, insulin normally inhibits which hepatic metabolic pathway during the fed state?',
  o:['Glycolysis','Gluconeogenesis','Glycogenesis','Lipogenesis'],a:1,
  e:`Gluconeogenesis is the hepatic pathway suppressed by insulin in the fed state: insulin activates the PI3K-Akt-FoxO1 axis, phosphorylating FoxO1 and preventing its nuclear entry, thereby suppressing transcription of PEPCK and glucose-6-phosphatase , the two key gluconeogenic enzymes.<br><br>Without this suppression, as in insulin deficiency or insulin resistance, the liver continues generating glucose from amino acids and glycerol even when blood glucose is already elevated, worsening hyperglycaemia.<br><br>Glycolysis (A), glycogenesis (C) and lipogenesis (D) are all insulin-stimulated pathways in the liver , insulin promotes, rather than inhibits, each of these anabolic reactions.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q14 , A=Increased fatty acid oxidation (keep)
  {q:'A pregnant woman develops diabetic ketoacidosis. Which metabolic process is primarily responsible for acetyl-CoA accumulation in the liver?',
  o:['Increased fatty acid oxidation','Increased glucose uptake','Increased glycolysis','Increased glycogen synthesis'],a:0,
  e:`In insulin deficiency, unrestrained lipolysis releases free fatty acids from adipose tissue into the circulation; hepatic uptake of these fatty acids drives beta-oxidation, generating large amounts of acetyl-CoA that exceed the capacity of the TCA cycle to oxidise them.<br><br>The surplus acetyl-CoA is then shunted into ketogenesis via HMG-CoA synthase, producing acetoacetate and beta-hydroxybutyrate , the substrates of diabetic ketoacidosis.<br><br>Glucose uptake (B) and glycolysis (C) are reduced in insulin deficiency; glycogen synthesis (D) requires insulin and is therefore suppressed in diabetic ketoacidosis.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q15 , B=Macrosomia (keep, but rotate to D for distribution)
  {q:'A fetus of a diabetic mother has increased insulin secretion leading to excessive anabolism. What is the most likely fetal outcome?',
  o:['Neural tube defects','Intrauterine growth restriction','Oligohydramnios','Macrosomia'],a:3,
  e:`Macrosomia , birthweight above 4 kg or above the 90th percentile , is the hallmark fetal complication of maternal diabetes, driven by fetal hyperinsulinaemia stimulating excessive glycogen storage, lipogenesis and protein synthesis in insulin-sensitive fetal tissues.<br><br>The resulting disproportionate truncal obesity with abdominal circumference exceeding head circumference is the characteristic ultrasound finding, predisposing to shoulder dystocia and operative delivery.<br><br>Neural tube defects (A) result from periconceptional hyperglycaemia and folate deficiency; IUGR (B) and oligohydramnios (C) are associated with placental insufficiency and pre-eclampsia rather than diabetic hyperinsulinaemia.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q16 , D=Gluconeogenesis , rotate to A to break with Q15=D
  {q:'A pregnant woman develops hypoglycemia after insulin therapy for gestational diabetes. Which compensatory hepatic pathway rapidly restores blood glucose?',
  o:['Gluconeogenesis','Lipogenesis','Glycogenesis','Glycolysis'],a:0,
  e:`Gluconeogenesis , synthesis of glucose from non-carbohydrate precursors including lactate, amino acids (particularly alanine) and glycerol , is the sustained hepatic response to hypoglycaemia, activated by glucagon and cortisol when insulin levels fall after therapy.<br><br>Alongside glycogenolysis (which provides the immediate glucose response), gluconeogenesis maintains blood glucose over hours, particularly when glycogen stores become depleted.<br><br>Lipogenesis (B) and glycogenesis (C) are anabolic pathways that consume rather than produce glucose; glycolysis (D) degrades glucose and would worsen hypoglycaemia rather than correct it.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q17 , C=Glycogen synthase (keep)
  {q:'Which enzyme activated by insulin promotes glycogen synthesis in hepatocytes?',
  o:['Glycogen phosphorylase','Pyruvate carboxylase','Glycogen synthase','Glucose-6-phosphatase'],a:2,
  e:`Glycogen synthase is activated by insulin through a dephosphorylation cascade: insulin activates protein phosphatase-1 (PP-1) via the PI3K-Akt pathway, which dephosphorylates and activates glycogen synthase while simultaneously inactivating glycogen phosphorylase , thereby switching the liver from glycogen breakdown to glycogen synthesis.<br><br>This dual regulation by a single phosphorylation state ensures that glycogen synthesis and breakdown cannot proceed simultaneously, preventing a futile cycle.<br><br>Glycogen phosphorylase (A) is inactivated by insulin; pyruvate carboxylase (B) catalyses the first step of gluconeogenesis; glucose-6-phosphatase (D) releases free glucose from the liver and is suppressed by insulin.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q18 , D=Glucose , rotate to B for distribution
  {q:'In pregnancy, insulin resistance develops partly to ensure increased transfer of which nutrient from mother to fetus?',
  o:['Fatty acids','Glucose','Ketone bodies','Amino acids'],a:1,
  e:`Physiological insulin resistance in late pregnancy reduces maternal glucose disposal by peripheral tissues, maintaining higher maternal glucose levels that increase the concentration gradient across the placenta, driving glucose transfer to the fetus via GLUT-1-mediated facilitated diffusion.<br><br>Glucose is the primary fetal fuel, accounting for approximately 70% of fetal energy requirements, with the fetus entirely dependent on maternal supply as it cannot perform significant hepatic gluconeogenesis in utero.<br><br>Fatty acids (A) cross the placenta but glucose is the primary substrate; ketone bodies (C) cross during maternal fasting; amino acids (D) are actively transported and serve as fetal building blocks rather than the primary energy substrate.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q19 , B=Increased lipolysis (keep)
  {q:'Which metabolic effect of insulin deficiency contributes to increased circulating free fatty acids in uncontrolled gestational diabetes?',
  o:['Increased glycogenesis','Increased lipogenesis','Increased glycolysis','Increased lipolysis'],a:3,
  e:`Insulin normally inhibits hormone-sensitive lipase (HSL) in adipose tissue; in insulin deficiency, HSL is disinhibited and actively hydrolyses stored triglycerides, releasing free fatty acids and glycerol into the circulation at rates exceeding peripheral utilisation.<br><br>These circulating free fatty acids are taken up by the liver and channelled into beta-oxidation, generating the acetyl-CoA that drives ketogenesis , the biochemical basis linking insulin deficiency to both hyperlipidaemia and ketonaemia.<br><br>Glycogenesis (A) and lipogenesis (B) require insulin and are suppressed in insulin deficiency; glycolysis (C) is reduced when insulin signalling is absent.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q20 , C=Persistent hyperinsulinemia (rotate to D for balance, avoid Q19=B,Q20=C)
  {q:'A fetus of a diabetic mother may develop neonatal hypoglycemia after birth. What is the primary biochemical mechanism?',
  o:['Increased glucagon secretion','Persistent hyperinsulinemia in the newborn','Reduced insulin secretion','Increased cortisol levels'],a:1,
  e:`Neonatal hypoglycaemia in infants of diabetic mothers results from persistent fetal hyperinsulinaemia: chronic intrauterine glucose oversupply has caused beta cell hypertrophy and hyperplasia, so when the placental glucose supply is abruptly cut at birth, the newborn continues secreting excess insulin against a suddenly reduced glucose input, driving blood glucose critically low.<br><br>This typically manifests within the first 1–2 hours of life and requires early feeding or intravenous dextrose to prevent seizures and neuroglycopaenia.<br><br>Glucagon secretion (A) is actually impaired in these infants; cortisol (D) is a counter-regulatory hormone whose levels are not specifically elevated; insulin secretion is increased, not reduced (C).<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q21 , B=Acetyl-CoA carboxylase (keep)
  {q:'Insulin stimulates fatty acid synthesis by activating which rate-limiting enzyme?',
  o:['Hormone-sensitive lipase','Lipoprotein lipase','Acetyl-CoA carboxylase','Carnitine palmitoyltransferase-I'],a:2,
  e:`Acetyl-CoA carboxylase (ACC) catalyses the carboxylation of acetyl-CoA to malonyl-CoA, the committed and rate-limiting step of de novo fatty acid synthesis. Insulin activates ACC both acutely (via dephosphorylation, reversing AMPK-mediated inhibition) and chronically (via SREBP-1c-mediated transcriptional upregulation).<br><br>The malonyl-CoA produced by ACC also inhibits carnitine palmitoyltransferase-I, preventing newly synthesised fatty acids from entering mitochondria for oxidation , ensuring synthesis and oxidation do not compete simultaneously.<br><br>Hormone-sensitive lipase (A) is inhibited by insulin; lipoprotein lipase (C) is activated by insulin but acts on circulating triglycerides; CPT-I (D) is inhibited when insulin stimulates fatty acid synthesis.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q22 , A=Malonyl-CoA (rotate to C for distribution)
  {q:'Insulin inhibits fatty acid oxidation mainly by increasing levels of which metabolic intermediate?',
  o:['Malonyl-CoA','NADH','Citrate','Acetyl-CoA'],a:0,
  e:`Malonyl-CoA , produced by insulin-activated acetyl-CoA carboxylase , directly inhibits carnitine palmitoyltransferase-I (CPT-I), the enzyme that transfers long-chain fatty acids across the inner mitochondrial membrane for beta-oxidation. Without CPT-I activity, fatty acids cannot enter the mitochondrial matrix and beta-oxidation is halted.<br><br>This elegant biochemical switch ensures that during the fed, high-insulin state, fatty acids are directed toward synthesis and storage rather than oxidation.<br><br>NADH (B) is a product of fatty acid oxidation; citrate (C) is exported from the TCA cycle to provide cytoplasmic acetyl-CoA for lipogenesis; acetyl-CoA (D) is the substrate entering the TCA cycle , none directly inhibit fatty acid entry into mitochondria.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q23 , D=PEPCK (keep)
  {q:'Insulin suppresses gluconeogenesis primarily by inhibiting transcription of which key enzyme?',
  o:['Hexokinase','Lactate dehydrogenase','Pyruvate kinase','Phosphoenolpyruvate carboxykinase'],a:3,
  e:`Phosphoenolpyruvate carboxykinase (PEPCK) catalyses the conversion of oxaloacetate to phosphoenolpyruvate, the committed step of gluconeogenesis in the cytoplasm. Insulin activates Akt, which phosphorylates and excludes FoxO1 from the nucleus, dramatically reducing PEPCK and glucose-6-phosphatase gene transcription.<br><br>In insulin resistance , as seen in gestational diabetes and type 2 diabetes , this suppression fails, leading to excessive hepatic glucose output that contributes significantly to fasting hyperglycaemia.<br><br>Hexokinase (A) and pyruvate kinase (C) are glycolytic enzymes stimulated by insulin; lactate dehydrogenase (B) interconverts pyruvate and lactate and is not a gluconeogenic enzyme.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q24 , B=PI3K-Akt (rotate to C for distribution)
  {q:'Which intracellular signaling pathway mediates insulin-induced GLUT-4 translocation to the plasma membrane?',
  o:['cAMP-PKA pathway','MAP kinase pathway','PI3K-Akt pathway','JAK-STAT pathway'],a:2,
  e:`The PI3K-Akt signalling cascade is the canonical pathway for insulin's metabolic actions: insulin binds its tyrosine kinase receptor, activating IRS-1/IRS-2 adaptor proteins that recruit PI3-kinase, generating PIP3 and activating Akt (protein kinase B). Akt then phosphorylates AS160, releasing its inhibition of Rab-GTPases that drive GLUT-4 vesicle fusion with the plasma membrane.<br><br>This pathway is specifically impaired in insulin resistance, explaining why GLUT-4 translocation and peripheral glucose uptake are defective in gestational diabetes and obesity.<br><br>cAMP-PKA (A) mediates glucagon and catecholamine actions; MAP kinase (B) mediates insulin's mitogenic effects; JAK-STAT (D) mediates cytokine signalling.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q25 , C=HMG-CoA synthase (keep)
  {q:'A pregnant woman with poorly controlled diabetes develops ketoacidosis. Increased acetyl-CoA in the liver is converted to ketone bodies by which key enzyme?',
  o:['Pyruvate dehydrogenase','Citrate synthase','Acetyl-CoA carboxylase','HMG-CoA synthase'],a:3,
  e:`HMG-CoA synthase catalyses the condensation of acetyl-CoA with acetoacetyl-CoA to form HMG-CoA in the mitochondria, the committed step of ketogenesis. This is followed by HMG-CoA lyase generating acetoacetate, which is reduced to beta-hydroxybutyrate or spontaneously decarboxylated to acetone.<br><br>In insulin deficiency, elevated glucagon and suppressed malonyl-CoA (from low ACC activity) remove the inhibition of CPT-I, maximising beta-oxidation and flooding the liver with acetyl-CoA that exceeds TCA cycle capacity, driving ketogenesis.<br><br>Pyruvate dehydrogenase (A) generates acetyl-CoA from pyruvate; citrate synthase (B) initiates the TCA cycle; acetyl-CoA carboxylase (C) produces malonyl-CoA for lipogenesis , none catalyse ketone body synthesis.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q26 , D=Gluconeogenesis (rotate to B to break future runs)
  {q:'In diabetic pregnancy, insulin deficiency leads to increased hepatic glucose output primarily through which pathway?',
  o:['Glycolysis','Gluconeogenesis','Glycogenesis','Pentose phosphate pathway'],a:1,
  e:`In insulin deficiency, the loss of FoxO1 suppression releases the transcriptional brake on PEPCK and glucose-6-phosphatase, allowing hepatic gluconeogenesis to proceed unchecked from amino acid (alanine, glutamine), glycerol and lactate substrates, constituting the dominant mechanism of fasting hyperglycaemia in diabetic pregnancy.<br><br>Glycogen depletion further accelerates this reliance on gluconeogenesis as the glycogen stores are exhausted early in fasting.<br><br>Glycolysis (A) generates, not produces, glucose; glycogenesis (C) stores glucose away from the circulation; the pentose phosphate pathway (D) diverts glucose-6-phosphate to ribose synthesis and NADPH production.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q27 , A=Maternal hyperglycemia crossing placenta (keep)
  {q:'A fetus exposed to maternal hyperglycemia develops hypertrophy of pancreatic beta cells. What is the primary trigger?',
  o:['Maternal hyperglycemia crossing the placenta','Maternal insulin crossing placenta','Maternal glucagon crossing placenta','Maternal cortisol crossing placenta'],a:0,
  e:`Glucose crosses the placenta by facilitated diffusion via GLUT-1 transporters, producing fetal glucose levels that closely mirror maternal concentrations. Chronic fetal hyperglycaemia directly stimulates fetal pancreatic beta cell proliferation (hyperplasia) and hypertrophy, increasing insulin secretory capacity , the Pedersen hypothesis of diabetic macrosomia.<br><br>This fetal beta cell adaptation explains why the consequences of poorly controlled maternal diabetes (macrosomia, neonatal hypoglycaemia) are mediated entirely by the fetal insulin response rather than maternal insulin directly.<br><br>Maternal insulin (B), glucagon (C) and cortisol (D) do not cross the placenta in significant quantities; only glucose serves as the primary transplacental signal.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q28 , C=Increased gluconeogenesis (rotate to A for distribution)
  {q:'Which metabolic change in maternal liver occurs when insulin signaling via PI3K-Akt is impaired, as in insulin resistance of pregnancy?',
  o:['Increased lipogenesis','Increased glycolysis','Increased gluconeogenesis','Increased glycogenesis'],a:2,
  e:`Impaired PI3K-Akt signalling fails to phosphorylate and exclude FoxO1 from the nucleus, allowing unrestrained transcription of PEPCK and glucose-6-phosphatase and therefore unchecked gluconeogenesis. This is the dominant hepatic consequence of insulin resistance in gestational diabetes, contributing to elevated fasting glucose.<br><br>Metformin's effectiveness in gestational diabetes relates partly to its inhibition of hepatic gluconeogenesis via AMPK activation and complex I inhibition in the mitochondrial respiratory chain.<br><br>Lipogenesis (A) and glycogenesis (D) require insulin signalling and are therefore impaired rather than increased; glycolysis (B) is modestly reduced when insulin action is blunted.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q29 , A=Increased glycogen synthesis (keep)
  {q:'Which metabolic effect of insulin promotes anabolic metabolism in maternal tissues after a meal?',
  o:['Increased gluconeogenesis','Increased lipolysis','Increased ketogenesis','Increased glycogen synthesis'],a:3,
  e:`Postprandial insulin release drives glycogen synthesis in liver and skeletal muscle as the primary immediate mechanism of glucose disposal.<br><br>In pregnancy, this anabolic insulin response is progressively blunted by physiological insulin resistance, necessitating higher insulin secretion to achieve the same glycogen synthetic effect , a mechanism that may unmask gestational diabetes in susceptible women.<br><br>Gluconeogenesis (A), lipolysis (B) and ketogenesis (C) are all counter-insulin catabolic pathways that dominate during fasting, not after a meal.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q30 , C=Increased glycogen storage and fat synthesis (rotate to D for distribution)
  {q:'A clinician explains that fetal macrosomia in diabetic pregnancy results from increased fetal insulin. Which combination of metabolic effects best explains the disproportionate abdominal enlargement?',
  o:['Increased lipolysis','Increased glycogen storage and fat synthesis','Increased gluconeogenesis','Increased ketone body production'],a:1,
  e:`Fetal hyperinsulinaemia simultaneously activates glycogen synthase (promoting hepatic and myocardial glycogen storage) and fatty acid synthase (driving subcutaneous and visceral fat deposition), both of which preferentially expand the fetal abdomen and trunk while sparing the head, explaining the asymmetric macrosomia characteristic of diabetic fetopathy.<br><br>Abdominal circumference measurement on ultrasound is therefore the most sensitive parameter for detecting macrosomia in diabetic pregnancy.<br><br>Lipolysis (A), ketone body production (D) and gluconeogenesis (C) are all catabolic counter-insulin pathways completely suppressed by the elevated fetal insulin in this setting.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q31 , D=Dephosphorylation (rotate to B for balance)
  {q:'Insulin activates glycogen synthase mainly through which biochemical mechanism?',
  o:['Phosphorylation','Proteolysis','Oxidation','Dephosphorylation'],a:3,
  e:`Glycogen synthase exists in phosphorylated (inactive) and dephosphorylated (active) forms. Insulin activates protein phosphatase-1 (PP-1) via the PI3K-Akt signalling cascade, which dephosphorylates glycogen synthase at multiple serine residues, converting it to the active form and driving glycogen synthesis.<br><br>This same PP-1 activation simultaneously dephosphorylates and inactivates glycogen phosphorylase, ensuring a coordinated switch from glycogen breakdown to synthesis without a futile cycle.<br><br>Phosphorylation (A) is the opposing glucagon/adrenaline-mediated action that inactivates glycogen synthase; proteolysis (B) and oxidation (C) are not physiological mechanisms for regulating this enzyme.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q32 , B=Fatty acid oxidation (keep)
  {q:'Which metabolic pathway becomes dominant in insulin deficiency leading to diabetic ketoacidosis in pregnancy?',
  o:['Glycolysis','Glycogenesis','Fatty acid oxidation','Lipogenesis'],a:2,
  e:`Beta-oxidation of fatty acids dominates in insulin deficiency: unopposed lipolysis releases free fatty acids from adipose tissue, which are taken up by the liver and mitochondrially oxidised via beta-oxidation. The resulting excess acetyl-CoA overwhelms the TCA cycle and is channelled into ketone body synthesis.<br><br>In pregnancy, the physiological tendency toward lipolysis and ketosis is amplified during fasting, explaining why pregnant women are more susceptible to ketoacidosis at lower blood glucose concentrations than non-pregnant individuals.<br><br>Glycolysis (A), glycogenesis (B) and lipogenesis (D) all require insulin for maximal activity and are therefore suppressed in insulin deficiency.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q33 , B=Lipid utilization , rotate to D to break Q32=B,Q33=B
  {q:'In insulin-resistant states of pregnancy, maternal metabolism shifts predominantly toward which fuel strategy to spare glucose for the fetus?',
  o:['Protein synthesis','Glycogen storage','Glucose utilization','Lipid utilization'],a:3,
  e:`Physiological insulin resistance in the third trimester redirects maternal energy metabolism toward lipid utilisation: increased lipolysis releases free fatty acids that maternal skeletal muscle and liver oxidise preferentially via beta-oxidation, sparing glucose for transplacental delivery to the fetus.<br><br>This "glucose-sparing" shift is sometimes called "accelerated starvation" and ensures fetal glucose supply is maintained even during periods of maternal fasting, at the cost of maternal ketonaemia.<br><br>Protein synthesis (A) and glycogen storage (B) require insulin and are relatively impaired; glucose utilisation (C) is specifically reduced in maternal tissues to preserve circulating glucose for fetal use.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q34 , C=Hormone-sensitive lipase (keep)
  {q:'Which enzyme responsible for triglyceride breakdown is inhibited by insulin in adipose tissue?',
  o:['Fatty acid synthase','Lipoprotein lipase','Hormone-sensitive lipase','Acetyl-CoA carboxylase'],a:2,
  e:`Hormone-sensitive lipase (HSL) is the rate-limiting intracellular lipase that hydrolyses stored triglycerides to diglycerides and then to free fatty acids and glycerol within adipocytes. Insulin inhibits HSL by activating phosphodiesterase-3B, which lowers cAMP levels and reduces PKA-mediated HSL phosphorylation and activation.<br><br>This is one of insulin's most potent anti-lipolytic actions , even low insulin concentrations are sufficient to significantly suppress HSL activity, explaining why small rises in insulin after meals effectively prevent inappropriate lipolysis.<br><br>Fatty acid synthase (A) and acetyl-CoA carboxylase (D) are lipogenic enzymes stimulated by insulin; lipoprotein lipase (B) is activated by insulin to hydrolyse circulating triglycerides for cellular uptake.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q35 , D=Tyrosine kinase receptor (rotate to A for balance)
  {q:'A pregnant woman with gestational diabetes has impaired insulin signaling. Which molecular structure represents the insulin receptor?',
  o:['Tyrosine kinase receptor','G-protein coupled receptor','Adenylate cyclase','Phospholipase C'],a:0,
  e:`The insulin receptor is a tetrameric transmembrane glycoprotein consisting of two alpha and two beta subunits linked by disulphide bonds; the beta subunits contain intrinsic tyrosine kinase domains. Insulin binding to the extracellular alpha subunits induces conformational change, activating the intracellular tyrosine kinase, which autophosphorylates the receptor and phosphorylates IRS-1 and IRS-2 adaptors to initiate the downstream PI3K-Akt signalling cascade.<br><br>Defects in insulin receptor tyrosine kinase activity, IRS phosphorylation or downstream signalling components underlie insulin resistance in gestational diabetes and type 2 diabetes.<br><br>G-protein coupled receptors (B) mediate glucagon, adrenaline and many hormone actions; adenylate cyclase (C) and phospholipase C (D) are downstream effectors of GPCRs, not insulin receptors.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q36 , C=Pentose phosphate pathway (keep)
  {q:'Which metabolic pathway stimulated by insulin provides NADPH required for fatty acid synthesis in maternal liver?',
  o:['Urea cycle','Glycolysis','Pentose phosphate pathway','Gluconeogenesis'],a:2,
  e:`The pentose phosphate pathway (PPP) , also called the hexose monophosphate shunt , diverts glucose-6-phosphate through oxidative reactions catalysed by glucose-6-phosphate dehydrogenase (G6PD) and 6-phosphogluconate dehydrogenase, generating NADPH as the primary reductive cofactor required by fatty acid synthase for de novo lipogenesis.<br><br>Insulin stimulates glucose flux through the PPP by promoting glucose uptake and glycolysis, increasing glucose-6-phosphate availability as PPP substrate, thereby coupling increased glucose supply to enhanced lipogenic capacity.<br><br>The urea cycle (A) detoxifies ammonia; glycolysis (B) generates pyruvate and ATP; gluconeogenesis (D) synthesises glucose , none generate NADPH for lipogenesis.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q37 , A=Lipolysis in adipose tissue (keep)
  {q:'In maternal metabolism, insulin suppresses ketone body production by inhibiting which upstream process?',
  o:['Lipolysis in adipose tissue','Glycolysis','Glycogen synthesis','Glucose uptake'],a:0,
  e:`Insulin suppresses ketogenesis primarily by inhibiting lipolysis in adipose tissue via HSL inactivation: without free fatty acid supply from adipose tissue, hepatic beta-oxidation is substrate-limited and acetyl-CoA production is insufficient to drive ketogenesis, regardless of hepatic enzyme activity.<br><br>This makes adipose tissue the primary metabolic regulator of ketone body production; even moderate rises in insulin sufficiently suppress HSL to dramatically reduce free fatty acid flux and prevent pathological ketosis.<br><br>Glycolysis (B) and glucose uptake (D) are insulin-stimulated and do not suppress ketogenesis; glycogen synthesis (C) is a hepatic action of insulin independent of ketogenic substrate supply.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q38 , D=Citrate (keep)
  {q:'Which metabolic intermediate produced by insulin-stimulated glycolysis and the TCA cycle serves as the precursor for cytoplasmic fatty acid synthesis?',
  o:['Pyruvate','Lactate','Oxaloacetate','Citrate'],a:3,
  e:`Citrate produced in the mitochondrial TCA cycle is exported to the cytoplasm via the citrate shuttle (tricarboxylate transport system) where it is cleaved by ATP-citrate lyase into acetyl-CoA and oxaloacetate. This cytoplasmic acetyl-CoA is then carboxylated by ACC to malonyl-CoA, the building block of de novo fatty acid synthesis.<br><br>This citrate shuttle elegantly couples glucose oxidation to fatty acid synthesis, explaining why insulin-stimulated glycolysis and lipogenesis are biochemically linked in the fed state.<br><br>Pyruvate (A) enters the mitochondria and feeds the TCA cycle; lactate (B) is a glycolysis endpoint; oxaloacetate (C) is recycled in the TCA cycle , none serve as the direct cytoplasmic acetyl-CoA donor for fatty acid synthesis.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q39 , C=Insulin (keep, rotate next)
  {q:'A fetus of a diabetic mother accumulates glycogen in the myocardium. Which fetal hormone drives this cardiac glycogen accumulation?',
  o:['Cortisol','Growth hormone','Insulin','Glucagon'],a:2,
  e:`Fetal insulin drives myocardial glycogen accumulation in infants of diabetic mothers by activating cardiac glycogen synthase and suppressing glycogen phosphorylase. Myocardial glycogen overload, combined with trophic insulin effects on cardiomyocyte hypertrophy, produces the hypertrophic cardiomyopathy (particularly interventricular septal hypertrophy) detectable on fetal echocardiography.<br><br>This typically resolves spontaneously within weeks to months after birth as hyperinsulinaemia resolves following removal of the maternal glucose source.<br><br>Cortisol (A) promotes glycogenolysis; growth hormone (B) is predominantly secreted postnatally and does not drive intrauterine myocardial glycogen storage; glucagon (D) promotes glycogenolysis and opposes storage.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q40 , D=Gluconeogenesis (rotate to A to break Q39=C,Q40=D run)
  {q:'During prolonged fasting in pregnancy, maternal liver maintains blood glucose levels primarily through which pathway?',
  o:['Gluconeogenesis','Lipogenesis','Glycolysis','Glycogenesis'],a:0,
  e:`During prolonged fasting, hepatic glycogen stores are exhausted within 12–18 hours, after which gluconeogenesis becomes the dominant pathway for maintaining blood glucose.<br><br>In pregnancy, gluconeogenesis is enhanced to compensate for the continuous fetal glucose drain, but this is partially offset by the physiological tendency toward ketosis as an alternative fetal fuel.<br><br>Lipogenesis (B) and glycogenesis (D) consume glucose; glycolysis (C) degrades glucose , none produce it.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q41 , B=Ketogenesis (rotate to D for balance)
  {q:'A pregnant woman with severe hyperemesis develops ketosis due to increased hepatic fatty acid oxidation. Which metabolic pathway produces ketone bodies?',
  o:['Glycolysis','Glycogenesis','Pentose phosphate pathway','Ketogenesis'],a:3,
  e:`Ketogenesis occurs in hepatic mitochondria: starvation-induced lipolysis releases free fatty acids that undergo beta-oxidation to acetyl-CoA. When acetyl-CoA exceeds TCA cycle capacity (due to low oxaloacetate from depleted glucose), HMG-CoA synthase condenses two acetyl-CoA molecules to HMG-CoA, which is then cleaved by HMG-CoA lyase to acetoacetate , the parent ketone body.<br><br>In hyperemesis gravidarum, the combination of vomiting-induced carbohydrate depletion and pregnancy-related physiological ketosis tendency accelerates this process, producing clinically significant ketonuria even without diabetes.<br><br>Glycolysis (A), glycogenesis (B) and the pentose phosphate pathway (C) are glucose-utilising pathways that do not generate ketone bodies.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q42 , C=Beta-oxidation (rotate to B for balance)
  {q:'During pregnancy, maternal tissues preferentially utilize fatty acids for energy through which pathway, sparing glucose for fetal use?',
  o:['Gluconeogenesis','Beta-oxidation','Glycolysis','Glycogenesis'],a:1,
  e:`Beta-oxidation is the stepwise mitochondrial degradation of fatty acids to acetyl-CoA units: each cycle shortens the fatty acyl chain by two carbons, generating one NADH, one FADH2 and one acetyl-CoA. These products feed into the TCA cycle and electron transport chain to generate ATP, allowing maternal tissues to meet their energy requirements without consuming glucose.<br><br>This fatty acid preference in maternal skeletal muscle and liver , driven by physiological insulin resistance , is the biochemical basis of the "glucose-sparing" adaptation of pregnancy that protects fetal glucose supply.<br><br>Gluconeogenesis (A) generates glucose; glycolysis (C) and glycogenesis (D) both consume glucose , none represent the fatty acid oxidation pathway.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q43 , D=Citric acid cycle (rotate to C)
  {q:'The placenta transfers glucose continuously from mother to fetus. Which metabolic pathway generates the majority of fetal ATP from this glucose under aerobic conditions?',
  o:['Glycolysis','Pentose phosphate pathway','Citric acid cycle and oxidative phosphorylation','Glycogenesis'],a:2,
  e:`The fetus oxidises glucose aerobically to maximise ATP yield: glycolysis converts glucose to pyruvate, generating 2 ATP; pyruvate dehydrogenase generates acetyl-CoA entering the TCA cycle; the 12 molecules of NADH and FADH2 produced per glucose molecule drive oxidative phosphorylation in the electron transport chain, producing 30–32 ATP per glucose molecule.<br><br>The fetus operates at a relatively low pO2 but under normal conditions generates most of its ATP oxidatively via this pathway, as evidenced by fetal CO2 production measurable in umbilical venous blood.<br><br>Glycolysis alone (A) generates only 2 net ATP; the PPP (B) diverts glucose to NADPH and ribose; glycogenesis (D) stores rather than oxidises glucose.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q44 , C=Glycogenesis (keep)
  {q:'A fetus of a diabetic mother accumulates excessive glycogen in the liver and myocardium. Which metabolic pathway is primarily upregulated by fetal hyperinsulinemia?',
  o:['Glycogenesis','Gluconeogenesis','Lipolysis','Glycogenolysis'],a:0,
  e:`Glycogenesis is the anabolic pathway through which glucose-6-phosphate is converted to UDP-glucose and then polymerised by glycogen synthase onto a glycogenin primer, forming branched glycogen chains. Fetal hyperinsulinaemia maximally activates glycogen synthase through dephosphorylation while concurrently inhibiting glycogen phosphorylase, driving net glycogen accumulation in the liver, myocardium and skeletal muscle.<br><br>Glycogen stores in the fetal liver increase fivefold in the last trimester under normal conditions, and this is pathologically amplified in infants of diabetic mothers.<br><br>Gluconeogenesis (B) and glycogenolysis (D) produce or release glucose; lipolysis (C) is an adipose tissue catabolic process , none represent the glycogen synthesis pathway.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q45 , D=Gluconeogenesis (rotate to A)
  {q:'In gestational diabetes, increased maternal glucose production results primarily from which hepatic pathway?',
  o:['Glycolysis','Pentose phosphate pathway','Gluconeogenesis','Lipogenesis'],a:2,
  e:`Hepatic gluconeogenesis is the dominant source of excess glucose production in gestational diabetes: insulin resistance impairs FoxO1 suppression, allowing PEPCK and glucose-6-phosphatase to remain transcriptionally active, generating glucose from lactate (Cori cycle), alanine (alanine cycle) and glycerol (from adipose lipolysis) even in the post-prandial state when this should be suppressed.<br><br>This unrestrained gluconeogenesis contributes to both fasting and post-prandial hyperglycaemia in GDM and is the primary target of metformin therapy.<br><br>Glycolysis (B) degrades glucose; the pentose phosphate pathway (C) diverts glucose-6-phosphate to ribose and NADPH; lipogenesis (D) stores excess glucose as fat , none generate new glucose.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q46 , B=Gluconeogenesis (rotate to D)
  {q:'During maternal starvation in pregnancy, amino acids from maternal muscle are converted into glucose primarily through which pathway?',
  o:['Ketogenesis','Lipogenesis','Glycolysis','Gluconeogenesis'],a:3,
  e:`Gluconeogenesis uses amino acid carbon skeletons as glucose precursors: alanine (the predominant gluconeogenic amino acid from muscle) is transaminated to pyruvate in the liver and fed into gluconeogenesis via pyruvate carboxylase (generating oxaloacetate) and PEPCK. Other glucogenic amino acids feed into TCA intermediates at multiple entry points.<br><br>The alanine cycle , alanine released from muscle, converted to glucose in the liver, and the nitrogen returned to muscle as glutamine , is the primary amino acid-based gluconeogenic pathway during fasting in pregnancy.<br><br>Ketogenesis (A) uses acetyl-CoA from fatty acids, not amino acids, to generate ketone bodies; lipogenesis (B) synthesises fatty acids; glycolysis (C) degrades glucose.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q47 , D=Beta-oxidation (rotate to B)
  {q:'A pregnant woman develops diabetic ketoacidosis with increased fatty acid breakdown. Which mitochondrial pathway generates the acetyl-CoA driving ketone body synthesis?',
  o:['Glycolysis','Beta-oxidation','Pentose phosphate pathway','Glycogenesis'],a:1,
  e:`Beta-oxidation sequentially cleaves long-chain fatty acyl-CoA chains within the mitochondrial matrix in a four-step cycle (oxidation, hydration, oxidation, thiolysis), releasing acetyl-CoA units. In insulin deficiency, CPT-I is disinhibited (low malonyl-CoA), maximising fatty acid import into the mitochondria and driving beta-oxidation at its maximum rate.<br><br>The resulting acetyl-CoA surplus, combined with depleted oxaloacetate (diverted to gluconeogenesis), overwhelms the TCA cycle and is redirected to HMG-CoA and then to ketone bodies.<br><br>Glycolysis (A), pentose phosphate pathway (C) and glycogenesis (D) are carbohydrate pathways that neither generate fatty acyl-CoA nor produce the acetyl-CoA driving ketogenesis.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q48 , B=Glycolysis (rotate to C)
  {q:'The fetus relies heavily on glucose metabolism. Which metabolic pathway directly converts glucose to pyruvate for energy generation?',
  o:['Gluconeogenesis','Glycogenesis','Glycolysis','Ketogenesis'],a:2,
  e:`Glycolysis is the cytoplasmic 10-step pathway converting glucose to pyruvate, generating 2 net ATP and 2 NADH per glucose molecule. In the fetus, glycolysis provides pyruvate that enters the TCA cycle via pyruvate dehydrogenase under aerobic conditions, or is reduced to lactate by LDH under anaerobic conditions, as occurs during hypoxia.<br><br>Fetal tissues have high glycolytic enzyme activity, particularly in the brain and heart, reflecting their heavy dependence on glucose as the primary energy substrate throughout intrauterine life.<br><br>Gluconeogenesis (A) is the reverse pathway, generating glucose from non-carbohydrate precursors; glycogenesis (B) polymerises glucose into glycogen for storage; ketogenesis (D) is a hepatic pathway generating ketone bodies from acetyl-CoA.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q49 , C=Ketogenesis (keep)
  {q:'A pregnant woman with prolonged fasting produces ketone bodies that can cross the placenta. Which pathway generates these ketone bodies?',
  o:['Ketogenesis','Glycolysis','Lipogenesis','Glycogenesis'],a:0,
  e:`Maternal hepatic ketogenesis produces acetoacetate and beta-hydroxybutyrate from excess acetyl-CoA during prolonged fasting; these small, water-soluble molecules freely cross the placenta and can substitute for glucose as a fetal brain fuel during maternal starvation , a physiological adaptation that protects fetal neurological function during periods of reduced maternal glucose availability.<br><br>The fetal liver cannot perform significant ketogenesis itself, making it entirely dependent on transplacental ketone supply during maternal starvation.<br><br>Lipogenesis (C) synthesises fatty acids and consumes, rather than generates, acetyl-CoA; glycolysis (B) generates pyruvate from glucose; glycogenesis (D) stores glucose as glycogen , none produce ketone bodies.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q50 , D=Cori cycle (rotate to B to break Q49=C,Q50=D)
  {q:'During pregnancy, maternal liver converts lactate produced by fetal metabolism into glucose via which metabolic cycle?',
  o:['Krebs cycle','Cori cycle','Alanine cycle','Urea cycle'],a:1,
  e:`The Cori cycle shuttles carbon between the fetus and maternal liver: fetal tissues produce lactate (via anaerobic glycolysis) that is exported into the umbilical circulation, taken up by the maternal liver, and converted to glucose via gluconeogenesis (lactate to pyruvate to oxaloacetate to phosphoenolpyruvate to glucose). This glucose is then returned via the placenta to the fetus.<br><br>The Cori cycle effectively allows the fetus to export its metabolic burden to the maternal liver during periods of relative fetal hypoxia or high glycolytic activity, maintaining fetal glucose supply.<br><br>The Krebs cycle (A) is the TCA cycle within cells; the alanine cycle (C) shuttles nitrogen via alanine; the urea cycle (D) detoxifies ammonia , none describe this lactate-glucose shuttle between fetus and mother.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q51 , D=Ketogenesis , rotate to A to break Q50=B,Q51=D
  {q:'In maternal metabolism during late pregnancy, increased fatty acid oxidation results in elevated levels of which metabolic products?',
  o:['Ketone bodies','Glycolysis products','Glycogen','Pentose sugars'],a:0,
  e:`Enhanced maternal fatty acid oxidation in late pregnancy, driven by physiological insulin resistance and increased adipose lipolysis, generates excess acetyl-CoA in the liver that exceeds TCA cycle capacity and is channelled into ketogenesis, elevating circulating acetoacetate and beta-hydroxybutyrate.<br><br>Even in normal pregnancy, fasting ketone levels are higher than in non-pregnant women, explaining the clinical phenomenon of "accelerated starvation" , pregnant women develop ketonaemia with shorter periods of fasting than non-pregnant women.<br><br>Glycolysis products (B), glycogen (C) and pentose sugars (D) are produced by carbohydrate pathways that are not directly related to fatty acid oxidation or its ketogenic consequences.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q52 , C=Pentose phosphate pathway (keep)
  {q:'Rapidly growing fetal tissues require ribose sugars for nucleotide synthesis. Which metabolic pathway provides these pentose sugars?',
  o:['Glycolysis','Beta-oxidation','Pentose phosphate pathway','Glycogenesis'],a:2,
  e:`The pentose phosphate pathway (PPP) diverts glucose-6-phosphate through the oxidative branch (generating NADPH and ribulose-5-phosphate) and the non-oxidative branch (generating ribose-5-phosphate), the five-carbon sugar required as the backbone of nucleotide and nucleic acid synthesis.<br><br>Rapidly proliferating fetal tissues have particularly high PPP flux to supply ribose-5-phosphate for DNA replication and RNA synthesis during organogenesis and growth, as well as NADPH for reductive biosynthesis and antioxidant defence.<br><br>Glycolysis (A) generates pyruvate; beta-oxidation (B) degrades fatty acids; glycogenesis (D) stores glucose as glycogen , none generate the ribose-5-phosphate required for nucleotide synthesis.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q53 , D=Gluconeogenesis (rotate to C)
  {q:'A pregnant woman with severe starvation develops increased glucose production from amino acids. Which pathway is primarily responsible?',
  o:['Glycolysis','Ketogenesis','Glycogenesis','Gluconeogenesis'],a:3,
  e:`Gluconeogenesis converts glucogenic amino acids , particularly alanine and glutamine from skeletal muscle breakdown , into glucose via the alanine cycle.<br><br>Alanine is transaminated in the liver to pyruvate, carboxylated to oxaloacetate by pyruvate carboxylase, converted to PEP by PEPCK, and finally dephosphorylated by glucose-6-phosphatase to release free glucose.<br><br>Glycolysis (A) degrades, not produces, glucose; ketogenesis (B) produces ketone bodies, not glucose; glycogenesis (C) stores glucose , none generate new glucose from amino acid precursors.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q54 , C=Citric acid cycle (keep)
  {q:'In maternal liver metabolism, acetyl-CoA produced from beta-oxidation enters which pathway for ATP generation under aerobic conditions?',
  o:['Glycolysis','Citric acid cycle','Glycogenesis','Pentose phosphate pathway'],a:1,
  e:`Acetyl-CoA from beta-oxidation condenses with oxaloacetate via citrate synthase to enter the TCA cycle (citric acid cycle / Krebs cycle), generating three NADH, one FADH2 and one GTP per acetyl-CoA. These reducing equivalents drive oxidative phosphorylation in the electron transport chain to produce the bulk of ATP for maternal energy demands.<br><br>In insulin deficiency, however, oxaloacetate is depleted (diverted to gluconeogenesis), limiting TCA cycle flux and redirecting excess acetyl-CoA to ketogenesis , the biochemical basis of why ketosis accompanies gluconeogenesis in diabetic ketoacidosis.<br><br>Glycolysis (A) generates pyruvate, not acetyl-CoA; the PPP (D) processes glucose-6-phosphate; glycogenesis (C) stores glucose , none accept acetyl-CoA as a substrate.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q55 , C=Lipogenesis , rotate to D to break Q54=C,Q55=C
  {q:'During pregnancy, increased citrate export from mitochondria promotes synthesis of which macromolecule class in the maternal liver?',
  o:['Fatty acids','Ketone bodies','Nucleotides','Glycolysis intermediates'],a:0,
  e:`Citrate exported from the mitochondrial TCA cycle via the tricarboxylate transport system is cleaved by ATP-citrate lyase in the cytoplasm to yield acetyl-CoA and oxaloacetate. This cytoplasmic acetyl-CoA is then carboxylated by ACC to malonyl-CoA and elongated by fatty acid synthase, directly coupling TCA cycle activity to de novo fatty acid synthesis in the fed state.<br><br>Insulin stimulates this entire sequence , increasing citrate export, ACC activity and fatty acid synthase expression , making lipogenesis the dominant fate of excess glucose in the post-prandial liver.<br><br>Ketone bodies (B) are produced when acetyl-CoA cannot be channelled into lipogenesis; nucleotides (C) require ribose from the PPP; glycolysis intermediates (D) are generated within the cytoplasm , none are the product of cytoplasmic citrate cleavage.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q56 , C=Pentose phosphate pathway (rotate to B to break Q55=D,Q56=C)
  {q:'Which metabolic pathway is primarily responsible for production of NADPH required for antioxidant defence in placental tissue?',
  o:['Glycolysis','Pentose phosphate pathway','Gluconeogenesis','Beta oxidation'],a:1,
  e:`The oxidative branch of the pentose phosphate pathway generates two molecules of NADPH per glucose-6-phosphate metabolised, catalysed by glucose-6-phosphate dehydrogenase and 6-phosphogluconate dehydrogenase. This NADPH is the essential cofactor for glutathione reductase, which regenerates reduced glutathione (GSH) from GSSG, maintaining the placenta's antioxidant capacity against reactive oxygen species.<br><br>The placenta has particularly high PPP activity due to its rapid cell turnover and exposure to both maternal and fetal oxidative stress, making NADPH generation via this pathway essential for placental function and fetal protection.<br><br>Glycolysis (A) and gluconeogenesis (C) do not generate NADPH; beta-oxidation (D) generates FADH2 and NADH but not the NADPH required for reductive biosynthesis and antioxidant regeneration.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q57 , D=Beta-oxidation (rotate to A to break future pair)
  {q:'A pregnant woman with uncontrolled diabetes develops increased fatty acid breakdown as the dominant hepatic pathway. Which term describes this process?',
  o:['Beta-oxidation','Glycolysis','Pentose phosphate pathway','Glycogenesis'],a:0,
  e:`Beta-oxidation is the mitochondrial pathway for fatty acid catabolism: long-chain fatty acids are esterified to CoA, transported into the mitochondrial matrix by CPT-I (rate-limiting step), and then sequentially oxidised by four enzymes (acyl-CoA dehydrogenase, enoyl-CoA hydratase, 3-hydroxyacyl-CoA dehydrogenase, thiolase) to yield acetyl-CoA, NADH and FADH2 per cycle.<br><br>In diabetic pregnancy, low malonyl-CoA from suppressed ACC activity removes the allosteric inhibition of CPT-I, allowing maximum fatty acid flux into beta-oxidation and driving the resulting ketoacidosis.<br><br>Glycolysis (B) degrades glucose; the pentose phosphate pathway (C) processes glucose-6-phosphate; glycogenesis (D) synthesises glycogen , none represent fatty acid oxidation.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q58 , D=Citric acid cycle , rotate to C to break Q57=A,Q58=D
  {q:'In fetal metabolism, which pathway generates ATP from acetyl-CoA under aerobic conditions to support fetal growth?',
  o:['Glycolysis','Gluconeogenesis','Citric acid cycle and oxidative phosphorylation','Glycogenesis'],a:2,
  e:`The TCA cycle oxidises acetyl-CoA (from glucose via pyruvate dehydrogenase) through a series of eight enzyme-catalysed reactions, generating three NADH, one FADH2 and one GTP per turn. The NADH and FADH2 feed into oxidative phosphorylation, generating approximately 34 ATP per glucose molecule via the electron transport chain and ATP synthase.<br><br>The fetus operates at a lower pO2 than adults but still relies predominantly on aerobic metabolism , as reflected by the high oxygen extraction from the umbilical circulation and significant fetal CO2 production.<br><br>Glycolysis (A) generates only 2 net ATP per glucose; gluconeogenesis (B) consumes rather than generates ATP; glycogenesis (D) stores glucose rather than oxidising it.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q59 , B=Glycogenolysis (rotate to D for balance)
  {q:'Which metabolic pathway converts glycogen into glucose-1-phosphate during maternal fasting to help maintain blood glucose?',
  o:['Glycolysis','Gluconeogenesis','Lipogenesis','Glycogenolysis'],a:3,
  e:`Glycogenolysis is catalysed by glycogen phosphorylase, which cleaves glucose residues from glycogen branch ends as glucose-1-phosphate (rapidly converted to glucose-6-phosphate by phosphoglucomutase), and the debranching enzyme, which removes branch point residues. In the liver, glucose-6-phosphate is then hydrolysed by glucose-6-phosphatase to release free glucose into the bloodstream.<br><br>Hepatic glycogenolysis provides the immediate glucose response to fasting (within minutes) before gluconeogenesis fully compensates; glycogen stores are exhausted after approximately 12–18 hours of fasting.<br><br>Glycolysis (A) and lipogenesis (C) consume glucose; gluconeogenesis (B) synthesises glucose from non-carbohydrate precursors , neither represent glycogen breakdown.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q60 , C=Phosphofructokinase-1 (rotate to B for distribution)
  {q:'In diabetic pregnancy, increased fatty acid oxidation generates large amounts of citrate and NADH that inhibit which key glycolytic enzyme?',
  o:['Hexokinase','Phosphofructokinase-1','Lactate dehydrogenase','Pyruvate kinase'],a:1,
  e:`Phosphofructokinase-1 (PFK-1) , the primary regulatory and rate-limiting enzyme of glycolysis , is allosterically inhibited by citrate and ATP, both of which accumulate when fatty acid oxidation is operating at high rates. This inhibition slows glycolysis, redirecting glucose-6-phosphate toward the pentose phosphate pathway or glycogen synthesis.<br><br>This biochemical cross-talk between fatty acid oxidation and glycolysis (the Randle cycle) is part of the mechanism by which increased fat utilisation in insulin-resistant or fasting states suppresses glucose oxidation, further elevating circulating glucose in diabetic pregnancy.<br><br>Hexokinase (A) is inhibited by its product glucose-6-phosphate; lactate dehydrogenase (C) interconverts pyruvate and lactate; pyruvate kinase (D) is the terminal glycolytic enzyme , none are the primary site of citrate-mediated glycolytic inhibition.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q61 , C=Alanine cycle (rotate to A to avoid run from batch1 end)
  {q:'During maternal fasting, alanine released from skeletal muscle is transported to the liver for glucose synthesis. Which metabolic cycle describes this process?',
  o:['Alanine cycle','Krebs cycle','Cori cycle','Urea cycle'],a:0,
  e:`The alanine cycle shuttles nitrogen and carbon between muscle and liver during fasting: transamination of pyruvate with glutamate in skeletal muscle produces alanine, which is exported to the liver where alanine aminotransferase reverses the reaction, regenerating pyruvate for gluconeogenesis and releasing the amino group for urea synthesis.<br><br>This cycle allows muscle to indirectly donate its nitrogen waste to the urea cycle while simultaneously supplying carbon skeletons to sustain hepatic gluconeogenesis during maternal fasting, protecting fetal glucose supply.<br><br>The Krebs cycle (B) is the TCA cycle within mitochondria; the Cori cycle (C) shuttles lactate between peripheral tissues and the liver; the urea cycle (D) detoxifies ammonia to urea.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q62 , B=Carnitine palmitoyltransferase-I (rotate to D for balance)
  {q:'In pregnancy, increased malonyl-CoA levels inhibit which enzyme involved in fatty acid transport into mitochondria?',
  o:['Citrate synthase','Lactate dehydrogenase','Pyruvate dehydrogenase','Carnitine palmitoyltransferase-I'],a:3,
  e:`Carnitine palmitoyltransferase-I (CPT-I) on the outer mitochondrial membrane transfers the fatty acyl group from acyl-CoA to carnitine, allowing transport across the inner mitochondrial membrane for beta-oxidation. Malonyl-CoA , produced by insulin-activated ACC , directly and potently inhibits CPT-I, preventing fatty acid entry into the mitochondria and thereby suppressing beta-oxidation during the fed state.<br><br>This allosteric inhibition of CPT-I by malonyl-CoA is the principal mechanism coordinating fatty acid synthesis and oxidation, ensuring they do not proceed simultaneously.<br><br>Citrate synthase (A) is the TCA cycle entry enzyme; lactate dehydrogenase (B) interconverts pyruvate and lactate; pyruvate dehydrogenase (C) converts pyruvate to acetyl-CoA , none are the fatty acid mitochondrial import enzyme.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q63 , C=Glycogen synthase (keep)
  {q:'A fetus exposed to maternal hyperglycemia accumulates excess glycogen in multiple organs. Which enzyme is primarily upregulated by fetal hyperinsulinemia?',
  o:['Hexokinase','Glycogen phosphorylase','Glycogen synthase','Glucose-6-phosphatase'],a:2,
  e:`Glycogen synthase is the primary target of fetal hyperinsulinaemia in driving glycogen accumulation: insulin activates protein phosphatase-1, which dephosphorylates and activates glycogen synthase while inactivating glycogen phosphorylase. This dual switch creates maximum net glycogen synthetic flux in the fetal liver, myocardium and skeletal muscle.<br><br>In infants of diabetic mothers, glycogen stores in these organs at birth are dramatically increased, predisposing to neonatal hypoglycaemia when this glycogen is rapidly depleted after the placental glucose supply is removed.<br><br>Hexokinase (A) phosphorylates glucose for glycolysis; glycogen phosphorylase (B) is inactivated by insulin; glucose-6-phosphatase (D) releases free glucose , all oppose glycogen accumulation.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q64 , B=Citric acid cycle (rotate to D for balance , avoiding Q63=C, Q64=B)
  {q:'During pregnancy, maternal metabolic adaptation results in increased reliance on which pathway for sustained ATP generation from fatty acid-derived substrates?',
  o:['Glycolysis','Pentose phosphate pathway','Glycogenesis','Citric acid cycle'],a:3,
  e:`As physiological insulin resistance shifts maternal metabolism toward lipid oxidation, the TCA cycle becomes the final common pathway for generating reducing equivalents (NADH and FADH2) from acetyl-CoA derived via beta-oxidation. These drive oxidative phosphorylation to produce the ATP required for maternal energy demands without consuming glucose.<br><br>This increased TCA cycle flux in maternal liver and muscle during pregnancy allows sustained energy generation while preserving glucose for transplacental fetal supply , the key metabolic adaptation of late pregnancy.<br><br>Glycolysis (A) generates pyruvate from glucose; the pentose phosphate pathway (B) generates NADPH and ribose; glycogenesis (C) stores glucose as glycogen , none sustain aerobic ATP generation from fatty acid-derived substrates.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q65 , A=Lactate dehydrogenase reaction (keep)
  {q:'In maternal liver metabolism, increased NADH generated from fatty acid oxidation drives which reaction to regenerate NAD+?',
  o:['Lactate dehydrogenase reaction','Pyruvate carboxylase reaction','PEP carboxykinase reaction','Glucose-6-phosphatase reaction'],a:0,
  e:`The lactate dehydrogenase (LDH) reaction reduces pyruvate to lactate using the excess NADH generated by beta-oxidation, regenerating NAD+ to allow continued glycolysis and the TCA cycle. The resulting lactate is exported to skeletal muscle and the Cori cycle or used as a gluconeogenic substrate.<br><br>In states of high fatty acid oxidation (insulin resistance, fasting, diabetic ketoacidosis), this elevated NADH/NAD+ ratio also inhibits gluconeogenic flux from lactate and contributes to lactic acidaemia.<br><br>Pyruvate carboxylase (B) converts pyruvate to oxaloacetate for gluconeogenesis; PEPCK (C) converts oxaloacetate to PEP; glucose-6-phosphatase (D) releases free glucose , none regenerate NAD+ from NADH produced by beta-oxidation.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q66 , B=HMG-CoA synthase (rotate to C)
  {q:'A pregnant woman with starvation ketosis has increased hepatic conversion of acetyl-CoA to ketone bodies. Which enzyme catalyses the committed step?',
  o:['Citrate synthase','Acetyl-CoA carboxylase','HMG-CoA synthase','Pyruvate dehydrogenase'],a:2,
  e:`Mitochondrial HMG-CoA synthase condenses acetyl-CoA with acetoacetyl-CoA to form HMG-CoA, the committed and rate-limiting step of ketogenesis. This enzyme is upregulated transcriptionally by glucagon (via cAMP) and suppressed by insulin, making it the primary site at which the fed/fasted state determines ketogenic flux.<br><br>In pregnancy, starvation rapidly induces ketogenesis due to the physiological insulin resistance and enhanced lipolysis, so blood and urine ketones rise more quickly and to higher concentrations than in the non-pregnant state.<br><br>Citrate synthase (A) initiates the TCA cycle; acetyl-CoA carboxylase (B) drives lipogenesis; pyruvate dehydrogenase (D) generates acetyl-CoA from pyruvate , none catalyse the committed step of ketone body synthesis.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q67 , D=Pentose phosphate pathway (rotate to B)
  {q:'Which metabolic pathway provides NADPH required for biosynthesis of steroids in maternal adrenal and gonadal tissues?',
  o:['Glycolysis','Pentose phosphate pathway','Gluconeogenesis','Beta oxidation'],a:1,
  e:`The oxidative pentose phosphate pathway generates NADPH via glucose-6-phosphate dehydrogenase and 6-phosphogluconate dehydrogenase; this NADPH is the obligate electron donor for the cytochrome P450 steroidogenic enzymes , cholesterol desmolase (CYP11A1), 17alpha-hydroxylase (CYP17A1), 21-hydroxylase (CYP21A2) and aromatase (CYP19A1) , that catalyse the sequential hydroxylation and oxidation steps of steroid hormone biosynthesis.<br><br>Steroidogenic tissues therefore have particularly high PPP activity, directly linking glucose metabolism to the biosynthetic capacity for oestrogen, progesterone, cortisol and testosterone.<br><br>Glycolysis (A) and gluconeogenesis (C) do not generate NADPH; beta-oxidation (D) generates FADH2 and NADH, not the NADPH required by steroidogenic cytochrome P450 enzymes.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q68 , D=Ketogenesis (rotate to A)
  {q:'In maternal metabolism during pregnancy, increased acetyl-CoA from fatty acid oxidation that exceeds TCA cycle capacity is channelled into which pathway?',
  o:['Ketogenesis','Glycolysis','Pentose phosphate pathway','Glycogenesis'],a:0,
  e:`When hepatic acetyl-CoA from beta-oxidation exceeds the capacity of the TCA cycle to oxidise it , either because oxaloacetate is depleted (diverted to gluconeogenesis) or because TCA flux is already maximal , the surplus acetyl-CoA is channelled into ketogenesis via HMG-CoA synthase, producing acetoacetate and beta-hydroxybutyrate.<br><br>In late pregnancy, physiological insulin resistance and the increased basal rate of lipolysis mean that even relatively brief fasting rapidly elevates maternal ketone levels above non-pregnant values, reflecting this accelerated shift toward ketogenesis.<br><br>Glycolysis (B) processes glucose, not acetyl-CoA; the pentose phosphate pathway (C) processes glucose-6-phosphate; glycogenesis (D) requires glucose input , none accept acetyl-CoA overflow.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q69 , C=Lipogenesis (rotate to D)
  {q:'Which metabolic pathway converts excess glucose into fatty acids in maternal liver during the early postprandial state?',
  o:['Glycolysis','Gluconeogenesis','Glycogenolysis','Lipogenesis'],a:3,
  e:`Lipogenesis (de novo fatty acid synthesis) is the post-prandial fate of excess glucose in the liver.<br><br>In pregnancy, the combination of physiological insulin surges after meals and increased appetite drives this lipogenic flux, contributing to the maternal fat deposition of the first two trimesters that serves as an energy reserve for late pregnancy and lactation.<br><br>Glycolysis (A) generates pyruvate; gluconeogenesis (B) synthesises glucose; glycogenolysis (C) releases glucose from glycogen , none convert excess glucose into fatty acids.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q70 , D=Maternal hyperglycemia crossing placenta (keep)
  {q:'A fetus exposed to maternal diabetes develops hypertrophy of pancreatic beta cells. What is the primary biochemical stimulus?',
  o:['Maternal insulin crossing placenta','Maternal cortisol crossing placenta','Maternal hyperglycemia crossing placenta','Maternal glucagon crossing placenta'],a:2,
  e:`Glucose is the primary transplacental signal for fetal pancreatic beta cell hypertrophy and hyperplasia: maternal glucose crosses the placenta freely via GLUT-1 facilitated diffusion, creating fetal hyperglycaemia that chronically stimulates fetal beta cell proliferation and insulin hypersecretion , the pathophysiological basis of diabetic macrosomia described by Pedersen.<br><br>Maternal insulin does not cross the placenta in significant amounts; the beta cell hypertrophy is therefore entirely a fetal response to the glucose stimulus, independent of maternal insulin levels.<br><br>Maternal insulin (A), cortisol (B) and glucagon (D) do not cross the placenta in physiologically relevant concentrations; only glucose reaches the fetus in amounts sufficient to drive this beta cell hypertrophic response.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q71 , C=Lipogenesis (rotate to A)
  {q:'During pregnancy, increased citrate transport from mitochondria into cytoplasm stimulates which anabolic pathway?',
  o:['Lipogenesis','Glycolysis','Ketogenesis','Glycogenesis'],a:0,
  e:`Citrate exported from the mitochondria via the tricarboxylate transport system is cleaved by ATP-citrate lyase in the cytoplasm to generate acetyl-CoA and oxaloacetate. The cytoplasmic acetyl-CoA is carboxylated by ACC to malonyl-CoA, the building block for de novo fatty acid synthesis by fatty acid synthase , directly coupling TCA cycle activity to lipogenesis in the insulin-stimulated fed state.<br><br>This citrate shuttle is the primary mechanism linking carbohydrate metabolism to fat synthesis, explaining why carbohydrate-rich diets drive fatty acid synthesis and triglyceride accumulation in the liver.<br><br>Glycolysis (B) generates pyruvate in the cytoplasm; ketogenesis (C) occurs in the mitochondria from excess acetyl-CoA; glycogenesis (D) polymerises glucose , none depend on cytoplasmic citrate cleavage for their substrate supply.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q72 , D=Pyruvate carboxylase (rotate to C)
  {q:'Which metabolic reaction converts pyruvate to oxaloacetate, the first committed step toward gluconeogenesis?',
  o:['Glycolysis','Pentose phosphate pathway','Pyruvate carboxylase reaction','Lipogenesis'],a:2,
  e:`Pyruvate carboxylase catalyses the ATP-dependent carboxylation of pyruvate to oxaloacetate in the mitochondrial matrix, the first step of gluconeogenesis from pyruvate and lactate. This biotin-dependent enzyme is activated by acetyl-CoA, creating a biochemical link between fatty acid oxidation and gluconeogenesis.<br><br>Excess acetyl-CoA from beta-oxidation simultaneously activates pyruvate carboxylase and inhibits pyruvate dehydrogenase, redirecting pyruvate toward glucose synthesis rather than TCA cycle entry. this coordination ensures that when fats are being oxidised for energy during fasting, glucose synthesis is simultaneously maintained.<br><br>Glycolysis (A) converts glucose to pyruvate , the reverse direction; PPP (B) generates ribose and NADPH; lipogenesis (D) synthesises fatty acids.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q73 , D=Citric acid cycle (rotate to B)
  {q:'Which metabolic pathway provides ATP and reducing equivalents necessary for active placental nutrient transport during pregnancy?',
  o:['Glycolysis','Citric acid cycle','Pentose phosphate pathway','Glycogenesis'],a:1,
  e:`The TCA cycle in placental trophoblast cells generates NADH and FADH2 from glucose-derived acetyl-CoA; these drive oxidative phosphorylation to produce the ATP required for the active transport of amino acids, calcium, iron and other nutrients against concentration gradients from mother to fetus.<br><br>The placenta has extraordinarily high metabolic activity , consuming approximately 40% of the oxygen and glucose delivered by the uterine artery , and its high TCA cycle flux supports both its own biosynthetic needs and the energy for active fetal-directed nutrient transport.<br><br>Glycolysis (A) generates only 2 net ATP and supports anaerobic conditions; PPP (C) generates NADPH for biosynthesis; glycogenesis (D) stores glucose , none provide the sustained, high-ATP output required for active placental transport.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q74 , C=Gluconeogenesis (keep)
  {q:'A pregnant woman with severe malnutrition produces glucose from amino acids to maintain blood glucose. Which hepatic pathway is responsible?',
  o:['Glycolysis','Ketogenesis','Gluconeogenesis','Glycogenesis'],a:2,
  e:`Gluconeogenesis converts amino acid carbon skeletons to glucose: transamination and deamination of glucogenic amino acids (alanine, glutamine, aspartate, serine and others) yield TCA intermediates or pyruvate that feed into gluconeogenesis via PEPCK and glucose-6-phosphatase, releasing free glucose into the circulation to protect the fetus and brain from hypoglycaemia during maternal malnutrition.<br><br>In severe maternal malnutrition, glucocorticoid-driven muscle protein catabolism increases amino acid supply, sustaining gluconeogenesis at the cost of progressive muscle wasting.<br><br>Glycolysis (A) degrades glucose; ketogenesis (B) produces ketone bodies from acetyl-CoA; glycogenesis (D) stores glucose , none produce glucose from amino acid precursors.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q75 , B=Citric acid cycle (rotate to D)
  {q:'Increased fatty acid oxidation in maternal tissues during pregnancy generates acetyl-CoA that enters which pathway for aerobic energy production?',
  o:['Glycolysis','Glycogenesis','Pentose phosphate pathway','Citric acid cycle'],a:3,
  e:`Acetyl-CoA from beta-oxidation of maternal fatty acids condenses with oxaloacetate via citrate synthase to enter the TCA cycle, generating 3 NADH, 1 FADH2 and 1 GTP per turn.<br><br>The shift from glucose to fatty acid oxidation in maternal tissues directly spares glucose for transplacental delivery to the fetus, making TCA cycle flux a key determinant of fetal glucose supply.<br><br>Glycolysis (A) processes glucose; glycogenesis (B) stores glucose; the PPP (C) generates NADPH and ribose , none aerobically oxidise acetyl-CoA to ATP.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q76 , C=Glycolysis (rotate to A to avoid future pair)
  {q:'In fetal metabolism, glucose is converted to lactate under anaerobic conditions by which pathway?',
  o:['Glycolysis','Gluconeogenesis','Glycogenesis','Lipogenesis'],a:0,
  e:`Glycolysis converts glucose to pyruvate; under hypoxic conditions in fetal tissues, lactate dehydrogenase reduces pyruvate to lactate using NADH as the cofactor, regenerating NAD+ to sustain continued glycolytic ATP production. Fetal tissues are particularly dependent on this anaerobic capacity during episodes of umbilical cord compression or placental insufficiency when oxygen delivery is transiently reduced.<br><br>The lactate produced is exported to the maternal Cori cycle for gluconeogenic recycling, preventing toxic accumulation while maintaining fetal ATP supply.<br><br>Gluconeogenesis (B) synthesises glucose from lactate in the maternal liver; glycogenesis (C) stores glucose; lipogenesis (D) synthesises fatty acids , none convert glucose to lactate under anaerobic conditions.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q77 , C=Glycogenolysis (rotate to B)
  {q:'Which metabolic pathway converts glycogen into glucose during maternal fasting to sustain blood glucose between meals?',
  o:['Glycolysis','Glycogenolysis','Lipogenesis','Ketogenesis'],a:1,
  e:`Glycogenolysis is catalysed by glycogen phosphorylase (activated by glucagon and adrenaline via cAMP-PKA), which cleaves glucose residues as glucose-1-phosphate, and the debranching enzyme, which removes alpha-1,6 branch points. In the liver, glucose-1-phosphate is converted to glucose-6-phosphate and hydrolysed by glucose-6-phosphatase, releasing free glucose into the portal circulation within minutes of glucagon stimulation.<br><br>Hepatic glycogenolysis is the first-line defence against hypoglycaemia; it provides glucose for approximately 12–18 hours before stores are depleted and gluconeogenesis must fully compensate.<br><br>Glycolysis (A) degrades glucose; lipogenesis (C) synthesises fatty acids; ketogenesis (D) produces ketone bodies , none release stored glycogen as glucose.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q78 , D=Ketogenesis (rotate to C)
  {q:'In maternal metabolism, increased fatty acid oxidation results in production of which metabolic products that can cross the placenta to serve as fetal fuel?',
  o:['Glycolysis products','Glycogen','Ketone bodies','Pentose phosphate products'],a:2,
  e:`Beta-hydroxybutyrate and acetoacetate , produced by maternal hepatic ketogenesis , are water-soluble and freely cross the placenta and blood-brain barrier by monocarboxylate transporters. In the fetus, they serve as an important alternative fuel to glucose during maternal fasting, particularly for fetal brain metabolism, reducing the fetal dependence on maternal glucose during periods of nutritional stress.<br><br>Fetal tissues, especially the brain, express beta-hydroxybutyrate dehydrogenase and can efficiently oxidise ketone bodies to acetyl-CoA for TCA cycle entry.<br><br>Glycolysis products (A) such as pyruvate and lactate are partially transferred but are not the primary ketogenesis-derived fetal fuel; glycogen (B) is not transferred across the placenta; PPP products (D) are not the lipid oxidation products.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q79 , D=Increased FAO with gluconeogenesis (rotate to B)
  {q:'Maternal metabolic adaptation during pregnancy ensures continuous glucose supply to the fetus. Which combination of maternal metabolic processes best describes the third-trimester adaptation?',
  o:['Increased glycolysis and glycogenesis','Increased fatty acid oxidation with increased gluconeogenesis','Increased pentose phosphate pathway and glycolysis','Increased glycogenolysis and lipogenesis'],a:1,
  e:`Third-trimester maternal metabolism is characterised by simultaneous enhancement of two complementary pathways: increased fatty acid oxidation (driven by physiological insulin resistance and adipose lipolysis) provides maternal energy while sparing glucose, and increased gluconeogenesis (from amino acids, glycerol and lactate) actively generates new glucose to replenish what the fetus continuously extracts via the placenta.<br><br>This combination , collectively termed "accelerated starvation" , allows the mother to maintain fetal glucose supply even during overnight fasting without significantly depleting her own blood glucose.<br><br>Glycolysis and glycogenesis (A) consume rather than spare glucose; the PPP and glycolysis (C) also consume glucose; glycogenolysis and lipogenesis (D) are incompatible at the enzymatic level and do not characterise third-trimester adaptation.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q80 , B=Pregnenolone (keep)
  {q:'Gonadal steroidogenesis begins with conversion of cholesterol into which initial steroid?',
  o:['Estradiol','Progesterone','Testosterone','Pregnenolone'],a:3,
  e:`Pregnenolone is the universal first steroid produced in all steroidogenic tissues: cholesterol desmolase (CYP11A1), located on the inner mitochondrial membrane, cleaves the side chain of cholesterol to yield pregnenolone. This is the committed, rate-limiting step of all steroid hormone biosynthesis and is dependent on the transport of cholesterol into the mitochondria by the StAR protein.<br><br>Pregnenolone is then exported to the smooth endoplasmic reticulum where it serves as the substrate for all subsequent steroidogenic pathways, including those producing progesterone, androgens, oestrogens and glucocorticoids.<br><br>Estradiol (A), progesterone (B) and testosterone (C) are all downstream products synthesised from pregnenolone via different enzymatic routes , none are the initial product of cholesterol metabolism.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q81 , C=Cholesterol desmolase CYP11A1 (keep)
  {q:'The rate-limiting enzyme responsible for conversion of cholesterol to pregnenolone in steroidogenesis is:',
  o:['Aromatase','21-hydroxylase','Cholesterol desmolase (CYP11A1)','17β-hydroxysteroid dehydrogenase'],a:2,
  e:`Cholesterol desmolase (CYP11A1) on the inner mitochondrial membrane catalyses the rate-limiting step of steroidogenesis, cleaving the C20-C22 bond of cholesterol to yield pregnenolone and isocaproaldehyde. This reaction requires NADPH (supplied by the pentose phosphate pathway) and molecular oxygen as cofactors, and is stimulated by LH in theca cells and FSH in granulosa cells via cAMP-mediated StAR protein upregulation.<br><br>Without adequate StAR-mediated cholesterol delivery to CYP11A1, steroidogenesis cannot proceed regardless of enzyme activity, explaining the severe steroid deficiency in congenital lipoid adrenal hyperplasia.<br><br>Aromatase (A) converts androgens to oestrogens; 21-hydroxylase (B) is essential for cortisol and aldosterone synthesis; 17β-HSD (D) interconverts weak and potent androgens and oestrogens.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q82 , D=Theca interna (keep, rotate next)
  {q:'In the ovary, androgen precursors are primarily produced by which cells under LH stimulation, according to the two-cell two-gonadotropin theory?',
  o:['Granulosa cells','Stromal macrophages','Luteal cells','Theca interna cells'],a:3,
  e:`LH binds receptors on theca interna cells, activating adenylate cyclase and increasing cAMP, which stimulates StAR-mediated cholesterol import into mitochondria. CYP11A1 converts cholesterol to pregnenolone, which is then converted to progesterone by 3β-HSD and to androstenedione and testosterone by 17α-hydroxylase and 17,20-lyase (CYP17A1) , the principal androgens produced by theca cells under LH stimulation.<br><br>These theca-derived androgens diffuse across the basement membrane into the granulosa cell compartment for FSH-stimulated aromatisation to oestrogens.<br><br>Granulosa cells (A) perform aromatisation under FSH but cannot produce significant androgens due to lack of CYP17A1; stromal macrophages (B) and luteal cells (C) are not the primary androgen-producing cells in the follicular phase.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q83 , B=Aromatase (rotate to C)
  {q:'Which enzyme converts androstenedione into estrone in ovarian granulosa cells?',
  o:['17α-hydroxylase','3β-hydroxysteroid dehydrogenase','Aromatase','11β-hydroxylase'],a:2,
  e:`Aromatase (CYP19A1) is a cytochrome P450 enzyme located in the smooth endoplasmic reticulum of granulosa cells that catalyses the three-step NADPH-dependent aromatisation of the A ring of androgens.<br><br>Androstenedione is converted to estrone, and testosterone is converted to estradiol. FSH stimulates aromatase expression in granulosa cells via cAMP-PKA signalling, making FSH the gonadotropin responsible for oestrogen synthesis in the follicle.<br><br>17α-hydroxylase (A) and 3β-HSD (B) are theca cell enzymes acting upstream of androgen production; 11β-hydroxylase (D) is an adrenal enzyme converting deoxycortisol to cortisol.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q84 , C=Theca and granulosa cells (rotate to A)
  {q:'The two-cell two-gonadotropin theory explains ovarian estrogen synthesis through coordinated action of which cell types?',
  o:['Theca and granulosa cells','Stromal fibroblasts and oocytes','Granulosa and luteal cells','Oocytes and stromal cells'],a:0,
  e:`The two-cell two-gonadotropin model describes how LH stimulates androgen production (androstenedione, testosterone) in theca interna cells, which lack the FSH receptors needed for aromatase stimulation. These androgens diffuse into the adjacent granulosa cells, which under FSH stimulation express aromatase (CYP19A1) and convert the theca-derived androgens to oestrogens , a biochemical collaboration across the basement membrane separating these two cell populations.<br><br>This is the basis for FSH and LH both being required for normal ovarian oestrogen synthesis.<br><br>Stromal fibroblasts and oocytes (B), granulosa and luteal cells (C), and oocytes and stromal cells (D) do not describe the LH-FSH steroidogenic collaboration central to this model.<br><br><em>(Gynaecology by Ten Teachers; Chapter: Physiology of the Menstrual Cycle)</em>`},
// Q85 , C=Cholesterol (rotate to D)
  {q:'In gonadal steroidogenesis, progesterone is synthesized mainly from which precursor?',
  o:['Cortisol','Estradiol','DHEA','Cholesterol'],a:3,
  e:`All steroid hormones, including progesterone, are synthesised from cholesterol as the universal precursor: cholesterol is transported into the mitochondria by StAR protein, converted to pregnenolone by CYP11A1, and then pregnenolone is converted to progesterone by 3β-hydroxysteroid dehydrogenase/isomerase (3β-HSD) in the smooth endoplasmic reticulum via oxidation of the 3-hydroxyl group and isomerisation of the double bond from the B ring to the A ring.<br><br>Progesterone is then a branch point from which both glucocorticoids and mineralocorticoids (in the adrenal) and androgens and oestrogens (in the ovary) are synthesised through tissue-specific enzyme expression.<br><br>Cortisol (A), estradiol (B) and DHEA (C) are downstream products of cholesterol , none serve as the precursor for progesterone synthesis.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q86 , D=PCOS (keep)
  {q:'Excess androgen production in ovaries leading to anovulation is most commonly associated with which condition?',
  o:['Turner syndrome','Polycystic ovary syndrome','Sheehan syndrome','Premature ovarian failure'],a:1,
  e:`Polycystic ovary syndrome (PCOS) is characterised by excess theca cell androgen production, driven by elevated LH stimulation and amplified by insulin resistance.<br><br>High LH hyperstimulates theca cell CYP17A1 activity, increasing androgen synthesis. Hyperinsulinaemia further augments LH-stimulated theca cell androgen production and simultaneously suppresses SHBG, increasing free androgen bioavailability. elevated intraovarian androgens disrupt aromatase-dependent follicular maturation, causing follicular arrest and anovulation , the primary mechanism of PCOS-related infertility.<br><br>Turner syndrome (A) and premature ovarian failure (D) are characterised by androgen deficiency and gonadal failure; Sheehan syndrome (C) is pituitary ischaemia causing gonadotropin deficiency , none involve excess ovarian androgen production.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q87 , B=Aromatase (rotate to D)
  {q:'Which enzyme deficiency prevents conversion of androgens into estrogens in ovarian granulosa cells?',
  o:['Aromatase','21-hydroxylase','11β-hydroxylase','17β-hydroxysteroid dehydrogenase'],a:0,
  e:`Aromatase (CYP19A1) is the sole enzyme capable of converting C19 androgens (androstenedione and testosterone) to C18 oestrogens (oestrone and oestradiol) through NADPH-dependent aromatisation of the steroid A ring. A deficiency of aromatase , due to mutations in the CYP19A1 gene , prevents oestrogen synthesis entirely, causing virilisation of female fetuses (from androgen accumulation), primary amenorrhoea, and maternal virilisation during affected pregnancies as placental androgens cannot be converted to oestrogens.<br><br>This enzyme deficiency is the biochemical basis for aromatase inhibitors (letrozole, anastrozole) used as ovulation induction agents in PCOS and adjuvant therapy in hormone receptor-positive breast cancer.<br><br>21-hydroxylase (B) and 11β-hydroxylase (C) are adrenal steroidogenic enzymes; 17β-HSD (D) interconverts potency within androgen and oestrogen classes but cannot perform aromatisation.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q88 , C=FSH (keep)
  {q:'Estrogen synthesis in ovarian granulosa cells primarily depends on which gonadotropin for aromatase stimulation?',
  o:['Prolactin','ACTH','FSH','LH'],a:2,
  e:`FSH binds its receptor on granulosa cells and activates adenylate cyclase via Gs protein, increasing intracellular cAMP. PKA activation then phosphorylates CREB and other transcription factors, upregulating CYP19A1 (aromatase) gene expression, enabling granulosa cells to convert theca-derived androgens (androstenedione, testosterone) to oestrogens (oestrone, oestradiol).<br><br>This FSH-aromatase axis is the principal mechanism of follicular oestrogen production and the molecular basis for FSH being the dominant follicle-stimulating and oestrogen-inducing gonadotropin in the follicular phase.<br><br>Prolactin (A) inhibits GnRH and gonadotropin secretion rather than stimulating aromatase; ACTH (B) stimulates adrenal steroidogenesis; LH (D) stimulates theca cell androgen production, not granulosa cell aromatase.<br><br><em>(Gynaecology by Ten Teachers; Chapter: Physiology of the Menstrual Cycle)</em>`},
// Q89 , D=Progesterone (rotate to C)
  {q:'Which steroid hormone predominates during the luteal phase of the menstrual cycle, preparing the endometrium for implantation?',
  o:['Estradiol','Progesterone','Testosterone','DHEA'],a:1,
  e:`Progesterone is secreted in large quantities by the corpus luteum after ovulation, reaching peak levels at approximately day 21 of a 28-day cycle. It acts on the progesterone-primed endometrium (previously prepared by oestrogen) to induce secretory transformation.<br><br>Stromal decidualisation, glandular secretion, increased vascularity and reduced contractility , all essential for blastocyst implantation. ongoing pituitary LH secretion sustains corpus luteum steroidogenesis, with progesterone levels remaining high for 12–14 days until corpus luteum regression if pregnancy does not occur.<br><br>Oestradiol (A) predominates in the follicular phase; testosterone (B) is present at low levels throughout the cycle; DHEA (D) is an adrenal androgen precursor , none are the dominant luteal phase hormone.<br><br><em>(Gynaecology by Ten Teachers; Chapter: Physiology of the Menstrual Cycle)</em>`},
// Q90 , B=PCOS (rotate to D)
  {q:'A woman with infertility is found to have high LH levels and increased ovarian androgen production but normal FSH. What is the most likely diagnosis?',
  o:['Turner syndrome','Hypothyroidism','Sheehan syndrome','PCOS'],a:3,
  e:`PCOS is characterised by a high LH-to-FSH ratio (typically greater than 2:1), elevated ovarian androgen production from hyperstimulated theca cells, and chronic anovulation. Biochemical evidence of hyperandrogenism , elevated testosterone, androstenedione or DHEAS , alongside raised serum LH levels and often raised insulin resistance markers is the hallmark clinical-biochemical combination in PCOS.<br><br>The high LH drives excess theca cell CYP17A1 activity, producing androgens that accumulate within follicles rather than being efficiently aromatised, disrupting follicular maturation and causing the polycystic morphology.<br><br>Turner syndrome (A) has elevated FSH and LH with primary ovarian failure; hypothyroidism (B) causes menstrual irregularity but not typically high LH; Sheehan syndrome (C) has low gonadotropins from pituitary necrosis.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q91 , D=Conversion of androgens to estrogens (keep)
  {q:'A patient with aromatase deficiency presents with virilization and low estrogen levels. Which specific enzymatic step is impaired?',
  o:['Conversion of progesterone to cortisol','Conversion of testosterone to DHT','Conversion of androgens to estrogens','Conversion of cholesterol to pregnenolone'],a:2,
  e:`Aromatase (CYP19A1) deficiency specifically abolishes the conversion of C19 androgens (androstenedione to oestrone; testosterone to oestradiol) by preventing NADPH-dependent A-ring aromatisation. The result is androgen accumulation and complete absence of oestrogen synthesis in ovarian granulosa cells and placenta, causing female virilisation, primary amenorrhoea, absent puberty and virilisation of the pregnant mother.<br><br>Placental aromatase is also essential for converting adrenal DHEAS to oestrogens during pregnancy; its absence causes the placenta to export androgens rather than oestrogens, explaining maternal virilisation in affected pregnancies.<br><br>Conversion of progesterone to cortisol (A) requires 21-hydroxylase and 11β-hydroxylase; testosterone to DHT (B) requires 5α-reductase; cholesterol to pregnenolone (D) requires CYP11A1 , none are impaired in aromatase deficiency.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q92 , C=Theca interna cells (rotate to B)
  {q:'A woman with ovarian tumor presents with virilization and high testosterone levels. The tumor cells most likely originate from which ovarian compartment?',
  o:['Granulosa cells','Theca interna cells','Oocytes','Stromal fibroblasts'],a:1,
  e:`Virilising ovarian tumours , particularly Sertoli-Leydig cell tumours (androblastomas) and steroid cell tumours , arise from or differentiate toward the theca/interstitial compartment, expressing CYP17A1 (17α-hydroxylase/17,20-lyase), which converts progesterone and pregnenolone to the androgens androstenedione and testosterone responsible for virilisation.<br><br>The elevated testosterone and androstenedione suppress the hypothalamic-pituitary axis via negative feedback, often reducing LH and FSH, while causing hirsutism, clitoromegaly, deepening of voice and menstrual irregularity in affected women.<br><br>Granulosa cells (A) primarily produce oestrogens and inhibin; oocytes (C) are germ cells; stromal fibroblasts (D) are support cells without significant steroidogenic enzyme expression.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q93 , B=Corpus luteum (keep)
  {q:'A patient with luteal phase defect presents with infertility due to inadequate progesterone. Which structure is primarily responsible for progesterone production after ovulation?',
  o:['Dominant follicle','Ovarian stroma','Theca externa','Corpus luteum'],a:3,
  e:`After ovulation, the ruptured follicle undergoes luteinisation: granulosa cells accumulate yellow lipid droplets (LDL-derived cholesterol) and markedly upregulate 3β-HSD, CYP11A1 and StAR, becoming the primary progesterone-secreting cells of the corpus luteum. LH receptor activation by pulsatile LH (and later hCG in pregnancy) drives sustained StAR-mediated cholesterol import and progesterone synthesis.<br><br>In luteal phase defect, inadequate LH support or granulosa cell insufficiency produces suboptimal progesterone levels, impairing endometrial decidualisation and blastocyst implantation , a treatable cause of recurrent early pregnancy loss.<br><br>The dominant follicle (A) produces oestrogen before ovulation; the ovarian stroma (B) produces small amounts of androgens; the theca externa (C) is a structural support layer with minimal steroidogenic activity.<br><br><em>(Gynaecology by Ten Teachers; Chapter: Physiology of the Menstrual Cycle)</em>`},
// Q94 , D=Loss of negative feedback (rotate to A)
  {q:'A woman with ovarian failure has elevated FSH and LH but low estrogen levels. What is the primary reason for the elevated gonadotropins?',
  o:['Loss of negative feedback from ovarian steroids','Increased prolactin secretion','Increased cortisol secretion','Increased thyroid hormone secretion'],a:0,
  e:`FSH and LH are normally suppressed by negative feedback from ovarian oestradiol (acting on both hypothalamus and anterior pituitary) and inhibin B (specifically suppressing FSH). In ovarian failure, the absence of functional follicles eliminates both oestradiol and inhibin B production, removing this negative feedback and allowing FSH and LH to rise to very high levels , the defining biochemical pattern of primary ovarian insufficiency and menopause.<br><br>FSH above 25–40 IU/L on two measurements confirms ovarian failure, and this elevation reflects the loss of gonadal steroid feedback rather than any primary pituitary over-activity.<br><br>Prolactin (B), cortisol (C) and thyroid hormone (D) do not specifically regulate FSH and LH through the ovarian feedback axis; their elevation causes suppression rather than elevation of gonadotropins.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q95 , B=Progesterone (rotate to C)
  {q:'Which ovarian steroid hormone exerts negative feedback on the hypothalamus and pituitary during the luteal phase?',
  o:['Testosterone','Estrone','Progesterone','DHEA'],a:2,
  e:`Progesterone secreted by the corpus luteum exerts negative feedback on the GnRH pulse generator in the hypothalamus, reducing GnRH pulse frequency and thereby suppressing LH and FSH secretion. This feedback, combined with oestradiol's negative feedback on gonadotropin amplitude, prevents a second LH surge and additional ovulation during the luteal phase.<br><br>This progesterone-mediated suppression of gonadotropin secretion stabilises the luteal phase and prevents premature follicular recruitment before the cycle is complete , its disruption in luteal phase defects contributes to infertility.<br><br>Testosterone (A) exerts some negative feedback but is not the primary luteal phase feedback hormone; estrone (B) is a weak oestrogen; DHEA (D) is an adrenal androgen precursor with minimal direct gonadotropin feedback.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q96 , C=FSH (keep, but rotate to D)
  {q:'Inhibin produced by ovarian granulosa cells primarily inhibits secretion of which anterior pituitary hormone?',
  o:['ACTH','LH','Prolactin','FSH'],a:3,
  e:`Inhibin B (the predominant form in the follicular phase) produced by granulosa cells selectively suppresses FSH secretion from the anterior pituitary without significantly affecting LH, providing the primary mechanism for FSH decline during mid-follicular phase. This selective FSH suppression assists in the selection of a single dominant follicle.<br><br>Inhibin B levels are used clinically as a marker of ovarian reserve , its decline with advancing age reflects the reducing granulosa cell mass before FSH rises become apparent.<br><br>ACTH (A), LH (B) and prolactin (C) secretion are not specifically regulated by ovarian inhibin.<br><br><em>(Gynaecology by Ten Teachers; Chapter: Physiology of the Menstrual Cycle)</em>`},
// Q97 , C=DHEA (rotate to A)
  {q:'Which steroid precursor produced in adrenal glands can be converted into estrogens in peripheral tissues?',
  o:['DHEA','Cortisol','Aldosterone','Progesterone'],a:0,
  e:`Dehydroepiandrosterone (DHEA) and its sulphate DHEAS are the most abundant adrenal androgens, secreted by the zona reticularis. In peripheral tissues , including skin, adipose tissue, liver and breast , DHEA is converted to androstenedione by 3β-HSD, then aromatised to oestrone by peripheral aromatase (CYP19A1), making DHEA the dominant precursor for extragonadal oestrogen synthesis in postmenopausal women and an important contributor to androgen excess in PCOS.<br><br>Adrenal DHEAS is also the primary substrate for placental oestrogen synthesis during pregnancy.<br><br>Cortisol (B) and aldosterone (C) are final-pathway adrenal steroids not converted to oestrogens; progesterone (D) is a progestogen whose downstream conversion products include androgens and glucocorticoids but not oestrogens in peripheral tissues.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q98 , B=5-alpha reductase (keep)
  {q:'Which enzyme converts testosterone into the more potent androgen dihydrotestosterone (DHT) in peripheral target tissues?',
  o:['Aromatase','5-alpha reductase','21-hydroxylase','17α-hydroxylase'],a:1,
  e:`5α-reductase (specifically type 2 isoform in genital and prostate tissue; type 1 in skin and liver) catalyses the irreversible NADPH-dependent reduction of the double bond between C4 and C5 of testosterone, producing dihydrotestosterone (DHT). DHT has approximately 5-fold higher binding affinity for the androgen receptor than testosterone and is the primary intracellular androgen mediating male genital virilisation, prostate growth and androgenic alopecia.<br><br>5α-reductase deficiency causes 46,XY individuals to be born with ambiguous genitalia (appear female at birth) but virilise at puberty when testosterone rises, as DHT-independent testosterone effects become apparent.<br><br>Aromatase (A) converts androgens to oestrogens; 21-hydroxylase (C) is an adrenal enzyme; 17α-hydroxylase (D) generates DHEA and androstenedione precursors , none convert testosterone to DHT.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q99 , C=Progesterone (rotate to D)
  {q:'Which steroid hormone is primarily responsible for preparation of endometrium for implantation during the secretory phase?',
  o:['Estradiol','Testosterone','Cortisol','Progesterone'],a:3,
  e:`Progesterone from the corpus luteum acts on oestrogen-primed endometrium to induce the secretory phase transformation: it promotes stromal decidualisation, glandular coiling and secretion, spiral artery development, and suppresses endometrial contractility, creating the receptive environment required for blastocyst implantation approximately 7 days after ovulation during the window of implantation.<br><br>Without adequate progesterone, the endometrium fails to decidualise properly, and blastocyst implantation fails , the clinical basis of luteal phase supplementation in assisted reproduction cycles.<br><br>Oestradiol (A) prepares the endometrium in the proliferative phase before ovulation; testosterone (B) has no endometrial preparatory role; cortisol (C) is a glucocorticoid without specific endometrial secretory function.<br><br><em>(Gynaecology by Ten Teachers; Chapter: Physiology of the Menstrual Cycle)</em>`},
// Q100 , C=Theca interna cells (rotate to B)
  {q:'In the two-cell two-gonadotropin model, LH stimulates androgen production in which ovarian cell type?',
  o:['Granulosa cells','Theca interna cells','Stromal fibroblasts','Luteal cells'],a:1,
  e:`Theca interna cells express LH receptors and respond to LH by upregulating StAR protein, CYP11A1 and CYP17A1, sequentially converting cholesterol to pregnenolone, progesterone, 17α-hydroxyprogesterone, androstenedione and testosterone. This theca cell androgen production is the essential androgen substrate that granulosa cells receive for aromatisation to oestrogens under FSH stimulation.<br><br>The two-cell theory explains why both FSH and LH are required for follicular oestrogen synthesis: FSH alone cannot produce oestrogen without LH-driven theca cell androgen substrate, and LH-stimulated androgens would accumulate without FSH-driven granulosa cell aromatase.<br><br>Granulosa cells (A) perform aromatisation under FSH but lack significant CYP17A1; stromal fibroblasts (C) and luteal cells (D) are not the primary androgen-producing cells during follicular development.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q101 , B=3β-HSD (keep)
  {q:'Which steroidogenic enzyme converts pregnenolone into progesterone?',
  o:['Aromatase','17β-hydroxysteroid dehydrogenase','3β-hydroxysteroid dehydrogenase','11β-hydroxylase'],a:2,
  e:`3β-hydroxysteroid dehydrogenase/isomerase (3β-HSD) catalyses the oxidation of the 3β-hydroxyl group and isomerisation of the double bond from the Δ5 to the Δ4 position, converting pregnenolone to progesterone. This enzyme is expressed in both mitochondria and endoplasmic reticulum of all steroidogenic tissues and is essential for the synthesis of all Δ4 steroids , progesterone, cortisol, aldosterone, testosterone and oestrogens.<br><br>3β-HSD deficiency causes congenital adrenal hyperplasia with impaired cortisol, aldosterone and sex steroid synthesis, presenting with salt-wasting and ambiguous genitalia.<br><br>Aromatase (A) converts C19 androgens to C18 oestrogens; 17β-HSD (B) interconverts weak and potent androgen or oestrogen pairs at the 17β-position; 11β-hydroxylase (D) is an adrenal enzyme adding a hydroxyl at C11.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q102 , D=Ovulation , rotate to C to break Q101=B, avoid Q102=D matching prev
  {q:'Excess androgen production in PCOS primarily interferes with which reproductive process?',
  o:['Fertilization','Ovulation','Implantation','Lactation'],a:1,
  e:`Excess intraovarian androgens from hyperstimulated theca cells disrupt follicular maturation by impairing FSH-stimulated granulosa cell aromatase activity, preventing the oestrogen production necessary for dominant follicle selection and the mid-cycle LH surge. The result is follicular arrest at the antral stage, producing the polycystic ovarian morphology on ultrasound and anovulation as the primary mechanism of PCOS-related infertility.<br><br>Increased ovarian androgen production suppresses follicular maturation primarily through disruption of granulosa cell aromatase activity rather than a direct effect on the oocyte or corpus luteum.<br><br>Fertilisation (A) is not the primary site of androgen interference; implantation (C) may be secondarily affected by inadequate progesterone; lactation (D) is unrelated to ovarian androgen excess.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q103 , D=hCG , rotate to A to break Q102=C, Q103=D
  {q:'Which hormone maintains the corpus luteum during early pregnancy before placental steroidogenesis is established?',
  o:['hCG','FSH','ACTH','Prolactin'],a:0,
  e:`Human chorionic gonadotropin (hCG) , produced by the syncytiotrophoblast of the implanting blastocyst , binds LH receptors on the corpus luteum and mimics LH signalling, preventing luteolysis and maintaining progesterone production through the first 8–10 weeks of pregnancy until the luteo-placental shift occurs and the placenta assumes steroidogenesis.<br><br>Serum hCG levels double approximately every 48 hours in early normal pregnancy, making the rate of rise a clinically important diagnostic marker for viable versus failing or ectopic pregnancy.<br><br>FSH (B), ACTH (C) and prolactin (D) do not maintain the corpus luteum; LH alone would be insufficient as its pulsatility is suppressed in early pregnancy by the high oestrogen and progesterone, making hCG's sustained LH-like action essential for corpus luteum rescue.<br><br><em>(Obstetrics by Ten Teachers)</em>`},
// Q104 , B=Aromatase deficiency (rotate to D)
  {q:'Which steroidogenic enzyme deficiency causes reduced estrogen production despite elevated androgen levels in ovarian tissue?',
  o:['21-hydroxylase deficiency','11β-hydroxylase deficiency','17β-hydroxylase deficiency','Aromatase deficiency'],a:3,
  e:`Aromatase deficiency (CYP19A1 mutations) abolishes the final enzymatic step converting androgens to oestrogens, causing androgen accumulation (elevated testosterone and androstenedione) alongside absent or very low oestrogen levels. In females, this presents with virilisation of the external genitalia, primary amenorrhoea and absent puberty; during pregnancy, the placenta accumulates androgens that cannot be aromatised, virilising the mother.<br><br>Aromatase inhibitors exploit this mechanism therapeutically , letrozole induces ovulation in PCOS by suppressing oestrogen feedback and thereby raising FSH, and is used as adjuvant therapy in oestrogen receptor-positive breast cancer.<br><br>21-hydroxylase (A) and 11β-hydroxylase (B) deficiencies cause adrenal hyperplasia with androgen excess but intact ovarian oestrogen; 17β-hydroxylase deficiency (C) impairs androgen production, not aromatisation.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q105 , B=GnRH , rotate to A to break Q104=D, Q105=B
  {q:'A woman with hyperprolactinemia develops infertility due to suppression of which hypothalamic hormone?',
  o:['GnRH','ACTH','TSH','GH'],a:0,
  e:`Hyperprolactinaemia suppresses GnRH pulsatility in the hypothalamus by enhancing endogenous opioid tone and direct inhibition of kisspeptin neurons, reducing LH and FSH secretion and impairing folliculogenesis. The resulting hypogonadotropic state produces oligo/amenorrhoea, anovulation and infertility , often reversible with dopamine agonist therapy (cabergoline, bromocriptine) which suppresses prolactin secretion.<br><br>Prolactin's physiological role is to suppress GnRH and permit lactational amenorrhoea, explaining why breastfeeding provides temporary contraception through this same mechanism.<br><br>ACTH (B), TSH (C) and GH (D) are not significantly suppressed by hyperprolactinaemia; the specificity of prolactin's effect on GnRH/kisspeptin neurons makes gonadotropin suppression the dominant endocrine consequence.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q106 , D=17β-HSD (keep)
  {q:'Which steroidogenic enzyme catalyzes conversion of androstenedione to testosterone?',
  o:['Aromatase','21-hydroxylase','11β-hydroxylase','17β-hydroxysteroid dehydrogenase'],a:3,
  e:`17β-hydroxysteroid dehydrogenase (17β-HSD, specifically type 3 in testis and type 1 in ovarian granulosa cells) catalyses the NADPH-dependent reduction of the 17-keto group of androstenedione to the 17β-hydroxyl group of testosterone, increasing androgenic potency approximately 5-fold. The same enzyme interconverts oestrone and oestradiol (the more potent oestrogen) in the 17β-position.<br><br>The conversion of androstenedione to testosterone by this enzyme in theca cells and the subsequent aromatisation of testosterone to oestradiol in granulosa cells represents the final steps of ovarian steroid synthesis in the two-cell model.<br><br>Aromatase (A) converts androgens to oestrogens; 21-hydroxylase (B) hydroxylates progesterone and 17α-OHP for cortisol and aldosterone synthesis; 11β-hydroxylase (C) is the adrenal enzyme adding the 11β-hydroxyl group.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q107 , A=Continuous endometrial proliferation (keep)
  {q:'A patient with estrogen-secreting ovarian tumor presents with abnormal uterine bleeding. What is the primary endometrial mechanism?',
  o:['Continuous endometrial proliferation without progesterone opposition','Reduced estrogen receptor sensitivity','Suppression of LH secretion','Increased androgen production'],a:0,
  e:`Unopposed oestrogen from a granulosa cell tumour or other oestrogen-secreting tumour drives continuous proliferative endometrial growth without the secretory transformation that requires progesterone opposition. Without cyclical progesterone withdrawal, the endometrium becomes hyperplastic and eventually breaks down irregularly, producing the heavy, irregular vaginal bleeding characteristic of oestrogen excess states.<br><br>Prolonged unopposed oestrogen stimulation is the primary risk factor for endometrial hyperplasia and carcinoma, explaining why progestogen supplementation is mandatory when oestrogen therapy is prescribed to women with an intact uterus.<br><br>Reduced oestrogen receptor sensitivity (B) would reduce, not cause, the proliferative response; LH suppression (C) is a consequence rather than the endometrial mechanism; increased androgen (D) would not drive endometrial proliferation.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q108 , C=FSH (rotate to A)
  {q:'Reduced granulosa cell aromatase activity leads to decreased estrogen synthesis. This impairs negative feedback, causing elevated levels of which gonadotropin?',
  o:['LH','FSH','ACTH','Prolactin'],a:1,
  e:`FSH secretion is specifically regulated by negative feedback from oestradiol (general suppression at the pituitary) and inhibin B (selective FSH suppression from granulosa cells). When granulosa cell aromatase activity is reduced , as in PCOS, ovarian failure or aromatase inhibitor therapy , oestradiol and inhibin B production falls, removing the negative feedback on FSH and causing its selective elevation relative to LH.<br><br>The resulting FSH rise in PCOS is paradoxically blunted by the elevated LH and androgens, producing the characteristic elevated LH:FSH ratio. In ovarian failure, both are elevated but FSH rises disproportionately.<br><br>LH (A) is regulated primarily by GnRH pulse frequency and oestradiol's positive/negative feedback; ACTH (C) and prolactin (D) are not regulated by ovarian oestrogen or inhibin feedback.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q109 , D=Conversion of cholesterol to pregnenolone (keep)
  {q:'Which metabolic step in gonadal steroidogenesis is considered rate-limiting?',
  o:['Conversion of testosterone to estradiol','Conversion of progesterone to cortisol','Conversion of androstenedione to testosterone','Conversion of cholesterol to pregnenolone'],a:3,
  e:`The conversion of cholesterol to pregnenolone by CYP11A1 (cholesterol desmolase) on the inner mitochondrial membrane is the rate-limiting step of steroidogenesis, controlled by the availability of cholesterol at the enzyme , which is determined by StAR protein-mediated transport across the mitochondrial membranes. Gonadotropin stimulation (LH in theca cells, FSH in granulosa cells) acutely upregulates StAR expression within minutes, making cholesterol delivery the primary acute regulatory point.<br><br>Long-term regulation involves transcriptional control of CYP11A1 itself, but the acute hormonal response to gonadotropin stimulation is mediated through StAR and cholesterol availability.<br><br>Testosterone to oestradiol (A) is regulated by aromatase; progesterone to cortisol (B) involves 21-hydroxylase and 11β-hydroxylase; androstenedione to testosterone (C) is catalysed by 17β-HSD , none are the rate-limiting step of steroidogenesis.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q110 , C=Hirsutism and virilization (rotate to A)
  {q:'Excess androgen secretion from ovarian tumors commonly leads to which clinical manifestation?',
  o:['Hirsutism and virilization','Amenorrhea with hypogonadism','Lactation failure','Galactorrhea'],a:0,
  e:`Excess androgens (testosterone, androstenedione) from virilising ovarian tumours such as Sertoli-Leydig cell tumours and steroid cell tumours cause hirsutism (androgen-sensitive hair follicle stimulation), acne, clitoromegaly, deepening of voice, amenorrhoea and muscle hypertrophy , the clinical constellation of androgen excess or virilisation. Testosterone values above 5–6 nmol/L (or rapidly rising values) in a virilised woman strongly suggest an androgen-secreting neoplasm rather than PCOS.<br><br>The clinical severity correlates with the degree and rate of testosterone elevation.<br><br>Amenorrhoea with hypogonadism (B) typically occurs in gonadal failure with low oestrogen; lactation failure (C) relates to prolactin deficiency; galactorrhoea (D) results from hyperprolactinaemia , none are caused by androgen excess.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q111 , D=Progesterone (rotate to C)
  {q:'Which steroid hormone is primarily synthesized by corpus luteum after ovulation to support the luteal phase?',
  o:['Testosterone','Estradiol','Progesterone','Cortisol'],a:2,
  e:`After ovulation, luteinised granulosa cells of the corpus luteum upregulate 3β-HSD, StAR and CYP11A1, making progesterone their dominant secretory product. Corpus luteal progesterone stabilises the decidualising endometrium, suppresses uterine contractility and inhibits premature LH surges via negative hypothalamic feedback, maintaining luteal phase integrity for 12–14 days pending hCG rescue if conception occurs.<br><br>In the absence of hCG, corpus luteum regresses after day 26 of a 28-day cycle, progesterone falls and menstruation ensues.<br><br>Testosterone (A) is produced in small amounts by the corpus luteum but is not its dominant secretory product; oestradiol (B) is also produced but at lower levels than progesterone in the mid-luteal phase; cortisol (D) is an adrenal, not corpus luteum, product.<br><br><em>(Gynaecology by Ten Teachers; Chapter: Physiology of the Menstrual Cycle)</em>`},
// Q112 , D=StAR , rotate to B to break Q111=C,Q112=D
  {q:'In gonadal steroidogenesis, cholesterol is transported into mitochondria by which protein?',
  o:['LDL receptor','Steroidogenic acute regulatory protein (StAR)','Cytochrome oxidase','Aromatase enzyme'],a:1,
  e:`Steroidogenic acute regulatory protein (StAR) is the acute regulatory protein that mediates the rapid import of cholesterol from the outer to the inner mitochondrial membrane, where CYP11A1 converts it to pregnenolone. StAR is rapidly synthesised within minutes of gonadotropin stimulation (via cAMP-PKA signalling), making it the acute rate-limiting determinant of steroid hormone production, often called the steroidogenic switch.<br><br>Mutations in the STAR gene cause congenital lipoid adrenal hyperplasia, characterised by complete absence of all steroid hormones and massive cholesterol ester accumulation in steroidogenic tissues.<br><br>The LDL receptor (A) imports cholesterol into the cell but does not transport it into mitochondria; cytochrome oxidase (C) is the terminal complex of the electron transport chain; aromatase (D) converts androgens to oestrogens in the smooth endoplasmic reticulum.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q113 , D=Transport of cholesterol into mitochondria , rotate to C to break Q112=B,Q113=D
  {q:'A defect in StAR protein leads to impaired synthesis of all steroid hormones. What specific function does StAR normally perform?',
  o:['Conversion of testosterone to estrogen','Conversion of androstenedione to testosterone','Transport of cholesterol into mitochondria','Conversion of progesterone to cortisol'],a:2,
  e:`StAR (steroidogenic acute regulatory protein) specifically facilitates the movement of cholesterol from the cytoplasm across the outer and inner mitochondrial membranes to the inner membrane surface where CYP11A1 resides, overcoming the hydrophobic barrier that would otherwise prevent cholesterol from accessing the enzyme. This cholesterol delivery is the rate-limiting, acutely regulated step of steroidogenesis in all steroidogenic tissues , adrenal, gonadal and placental.<br><br>Without StAR, cholesterol cannot reach CYP11A1 in sufficient quantities regardless of enzyme activity, explaining why StAR mutations abolish synthesis of cortisol, aldosterone, oestrogen, progesterone and testosterone simultaneously.<br><br>Testosterone to oestrogen conversion (A) is performed by aromatase; androstenedione to testosterone (B) by 17β-HSD; progesterone to cortisol (D) requires 21-hydroxylase and 11β-hydroxylase , none are StAR's function.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q114 , A=LH (keep)
  {q:'Which hormone stimulates androgen production in ovarian theca cells during follicular development?',
  o:['LH','FSH','Prolactin','ACTH'],a:0,
  e:`LH binds Gs-coupled receptors on theca interna cells, activating adenylate cyclase to generate cAMP and activate PKA. PKA phosphorylates and activates StAR (acutely) and upregulates CYP17A1 (17α-hydroxylase/17,20-lyase) transcriptionally, enabling the sequential conversion of cholesterol to androstenedione and testosterone , the androgens that diffuse into granulosa cells for FSH-stimulated aromatisation.<br><br>In PCOS, excessive LH stimulation of theca cells (amplified by hyperinsulinaemia) is the primary driver of androgen excess, as CYP17A1 is upregulated beyond physiological requirements.<br><br>FSH (B) stimulates granulosa cell aromatase; prolactin (C) inhibits GnRH and suppresses gonadotropin secretion; ACTH (D) stimulates adrenal steroidogenesis , none stimulate ovarian theca androgen production via the LH receptor pathway.<br><br><em>(Gynaecology by Ten Teachers; Chapter: Physiology of the Menstrual Cycle)</em>`},
// Q115 , D=Disruption of granulosa cell aromatase (rotate to B)
  {q:'Increased ovarian androgen production suppresses follicular maturation primarily through which mechanism?',
  o:['Increased thyroid hormone activity','Disruption of granulosa cell aromatase activity','Increased progesterone synthesis','Increased prolactin secretion'],a:1,
  e:`Excess intraovarian androgens inhibit granulosa cell aromatase (CYP19A1) activity and FSH-stimulated follicular development, preventing the rise in intrafollicular oestrogen concentration needed for dominant follicle selection, LH receptor induction and the pre-ovulatory LH surge. The follicle arrests at the antral stage, accumulates androgen rather than oestrogen, and the surrounding granulosa cells undergo premature atresia.<br><br>This androgen-mediated disruption of aromatase activity within developing follicles is the central biochemical mechanism linking theca cell hyperfunction in PCOS to anovulation and infertility.<br><br>Thyroid hormone (A) and prolactin (D) impair folliculogenesis through neuroendocrine rather than intraovarian mechanisms; increased progesterone synthesis (C) would reflect luteinisation rather than androgen excess-mediated arrest.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q116 , B=Estradiol (rotate to D)
  {q:'Which steroid hormone derived from testosterone is responsible for development of female secondary sexual characteristics at puberty?',
  o:['Progesterone','Cortisol','DHEA','Estradiol'],a:3,
  e:`Oestradiol (17β-oestradiol) , synthesised from testosterone by aromatase in ovarian granulosa cells , is the predominant oestrogen responsible for female secondary sexual characteristics.<br><br>Oestradiol has the highest binding affinity for oestrogen receptors ERα and ERβ of all natural oestrogens, making it the most potent and clinically relevant oestrogen throughout reproductive life.<br><br>Progesterone (A) prepares the endometrium for implantation; cortisol (B) is a glucocorticoid; DHEA (C) is an androgen precursor , none are the primary oestrogen driving female secondary sexual development.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q117 , A=Aromatase (keep)
  {q:'In steroidogenesis, which cytochrome P450 enzyme converts androgens into estrogens?',
  o:['Aromatase','21-hydroxylase','11β-hydroxylase','17α-hydroxylase'],a:0,
  e:`Aromatase (CYP19A1) is the P450 enzyme that catalyses the rate-limiting and irreversible aromatisation of the A ring of C19 androgens to form C18 oestrogens.<br><br>Androstenedione to oestrone and testosterone to oestradiol, each requiring three NADPH molecules and molecular oxygen per reaction. Aromatase is expressed in granulosa cells (FSH-stimulated), placenta, adipose tissue, liver, bone, brain and breast , making it the primary determinant of whole-body oestrogen production.<br><br>21-hydroxylase (B) and 11β-hydroxylase (C) are adrenal enzymes in the cortisol/aldosterone pathway; 17α-hydroxylase (D) generates androgen precursors upstream of aromatase , none perform androgenic A-ring aromatisation.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q118 , D=Theca interna cells (rotate to C)
  {q:'In PCOS, increased ovarian androgen production mainly results from excessive stimulation of which cell type?',
  o:['Granulosa cells','Oocytes','Theca interna cells','Stromal macrophages'],a:2,
  e:`In PCOS, elevated LH levels hyperstimulate theca interna cells, upregulating CYP17A1 (17α-hydroxylase/17,20-lyase) beyond normal levels and producing excess androstenedione and testosterone. Hyperinsulinaemia amplifies this by directly stimulating theca cell LH receptors and CYP17A1 activity through insulin receptor and IGF-1 receptor signalling, as insulin and IGF-1 act as co-gonadotropins in these cells.<br><br>The resulting excess theca-derived androgens overwhelm the aromatase capacity of the granulosa cells, accumulate intrafolliclularly and in the circulation, causing the clinical and biochemical features of PCOS.<br><br>Granulosa cells (A) perform aromatisation but do not express CYP17A1 and do not produce androgens in excess in PCOS; oocytes (B) and stromal macrophages (D) are not androgen-producing cells.<br><br><em>(Gynaecology by Ten Teachers)</em>`},
// Q119 , C=Infertility due to anovulation (rotate to A)
  {q:'A reproductive endocrinologist explains that ovarian estrogen production requires both FSH-stimulated granulosa cells and LH-stimulated theca cells. What does failure of this collaboration primarily cause?',
  o:['Infertility due to anovulation','Dysmenorrhea','Postcoital bleeding','Lactation failure'],a:0,
  e:`Failure of the two-cell two-gonadotropin collaboration impairs oestrogen production: without theca-derived androgenic substrate, granulosa cell aromatase has no material to convert.<br><br>This biochemical framework underpins the use of FSH (to stimulate granulosa aromatase) and LH supplementation (to support theca androgen production) in ovulation induction protocols for hypogonadotropic hypogonadism.<br><br>Dysmenorrhoea (B) is caused by endometrial prostaglandins in ovulatory cycles; postcoital bleeding (C) suggests cervical pathology; lactation failure (D) involves prolactin and oxytocin , none result from failure of the two-cell steroidogenic collaboration.<br><br><em>(Gynaecology by Ten Teachers; Chapter: Physiology of the Menstrual Cycle)</em>`},
// Q120 , NEW MCQ to reach 120 total
  {q:'Which placental enzyme is responsible for converting maternal DHEAS into estrogens during pregnancy?',
  o:['21-hydroxylase','Aromatase','11β-hydroxylase','3β-hydroxysteroid dehydrogenase'],a:1,
  e:`Placental aromatase (CYP19A1) is the primary enzyme driving placental oestrogen synthesis: adrenal DHEAS from both the mother and fetus is sulphatase-cleaved to DHEA, converted to androstenedione by 3β-HSD, and then aromatised to oestrone and oestradiol by placental aromatase. In the case of 16α-hydroxy-DHEAS (predominantly from the fetal adrenal), aromatase produces the pregnancy-specific oestrogen oestriol (E3).<br><br>Oestriol levels reflect combined fetal adrenal and placental function, making it an indirect marker of fetal wellbeing , its decline is associated with fetal adrenal insufficiency, anencephaly and placental sulphatase deficiency.<br><br>21-hydroxylase (A) and 11β-hydroxylase (C) are adrenal enzymes in the cortisol pathway; 3β-HSD (D) acts upstream of aromatase, converting DHEA to androstenedione, but does not itself produce oestrogens.<br><br><em>(Obstetrics by Ten Teachers)</em>`}
  ];
})();
